-- =============================================================================
-- bootstrap-byo-schema.sql  (v2.1 — dependency-ordered, as-applied)
-- =============================================================================
-- Assembled from the Task #37 v2 extraction against Lovable Cloud prod
--   Source: bfmyebsjyuoecmjskqhs (Paige Agent AI)   Target: BYO xygzykjyynhzqytbqnzu
-- Applied successfully 2026-07-05 (sanity: 251 tables / 214 functions / 750 policies).
--
-- APPLY ORDER (dependency-correct; section IDs preserved):
--   01 ext -> 02 enums -> 03 seq -> 04 tables -> 05 pk/uniq -> 06 fk -> 07 checks
--   -> 08a table indexes -> 09a functions(no relation sigs) -> 11 views+matviews
--   -> 08b matview indexes -> 09b functions(relation sigs) -> 10 triggers
--   -> 12 rls -> 13 grants -> 14 comments
--
-- FIVE CORRECTIONS vs the original flat extraction (all Task #37 apply-time findings):
--   1. §08 split: table indexes (08a) before views; matview indexes (08b) AFTER §11.
--   2. §09 prepend: SET check_function_bodies = false (pg_dump-standard body deferral).
--   3+4. §09 two-phase split: 09a = 211 functions with no relation-rowtype signature;
--        09b = 3 functions RETURNS SETOF <matview/view> applied AFTER §11.
--   5. §13 grants: managed-platform roles filtered (absent on BYO; 1,492 dropped / 9,215 kept).
-- Run against a FRESH empty public schema.
-- =============================================================================

-- §01 EXTENSIONS
-- =============================================================================

CREATE EXTENSION IF NOT EXISTS "uuid-ossp" WITH SCHEMA extensions;
CREATE EXTENSION IF NOT EXISTS pg_cron WITH SCHEMA pg_catalog;
CREATE EXTENSION IF NOT EXISTS pg_net WITH SCHEMA extensions;
CREATE EXTENSION IF NOT EXISTS pg_stat_statements WITH SCHEMA extensions;
CREATE EXTENSION IF NOT EXISTS pgcrypto WITH SCHEMA extensions;
CREATE EXTENSION IF NOT EXISTS pgmq WITH SCHEMA pgmq;
CREATE EXTENSION IF NOT EXISTS supabase_vault WITH SCHEMA vault;
CREATE EXTENSION IF NOT EXISTS vector WITH SCHEMA extensions;


