  id uuid DEFAULT gen_random_uuid() NOT NULL,
  user_id uuid NOT NULL,
  role app_role DEFAULT 'user'::app_role NOT NULL,
  created_at timestamp with time zone DEFAULT now());
CREATE TABLE IF NOT EXISTS public.user_subscriptions (
  id uuid DEFAULT gen_random_uuid() NOT NULL,
  user_id uuid NOT NULL,
  plan_slug text NOT NULL,
  status text DEFAULT 'trial'::text NOT NULL,
  trial_ends_at timestamp with time zone,
  current_period_start timestamp with time zone,
  current_period_end timestamp with time zone,
  stripe_subscription_id text,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now());
CREATE TABLE IF NOT EXISTS public.user_usage (
  id uuid DEFAULT gen_random_uuid() NOT NULL,
  user_id uuid NOT NULL,
  disputes_used integer DEFAULT 0,
  ai_chats_used integer DEFAULT 0,
  reset_at timestamp with time zone DEFAULT now(),
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now());
CREATE TABLE IF NOT EXISTS public.vendor_offers (
  id uuid DEFAULT gen_random_uuid() NOT NULL,
  name text NOT NULL,
  category text NOT NULL,
  benefits text,
  apply_url text NOT NULL,
  affiliate_tag text,
  requirements text,
  is_active boolean DEFAULT true,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now());
CREATE TABLE IF NOT EXISTS public.voice_command_logs (
  id uuid DEFAULT gen_random_uuid() NOT NULL,
  user_id uuid NOT NULL,
  turn_id text NOT NULL,
  utterance text NOT NULL,
  intent text,
  scope text,
  slots jsonb DEFAULT '{}'::jsonb,
  action jsonb,
  status text NOT NULL,
  latency_ms integer,
  confirmation_required boolean DEFAULT false,
  created_at timestamp with time zone DEFAULT now());
CREATE TABLE IF NOT EXISTS public.webhook_event_log (
  id uuid DEFAULT gen_random_uuid() NOT NULL,
  direction text NOT NULL,
  event_type text NOT NULL,
  target_url text,
  payload_summary jsonb,
  request_payload jsonb,
  response_body text,
  http_status integer,
  status text DEFAULT 'pending'::text NOT NULL,
  retry_count integer DEFAULT 0 NOT NULL,
  created_at timestamp with time zone DEFAULT now() NOT NULL);


