CREATE OR REPLACE FUNCTION public._assert_billing_admin()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.uid() IS NULL THEN RAISE EXCEPTION 'not authenticated'; END IF;
  IF NOT (public.has_role(auth.uid(),'admin'::app_role)
       OR public.has_role(auth.uid(),'owner'::app_role)
       OR public.is_platform_owner(auth.uid())) THEN
    RAISE EXCEPTION 'billing admin role required';
  END IF;
  IF NOT public.tenant_has_feature('billing_enabled') THEN
    RAISE EXCEPTION 'billing_enabled feature is not active for this tenant';
  END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public._automation_webhook_key()
 RETURNS text
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE _key text;
BEGIN
  SELECT value INTO _key FROM public._internal_secrets WHERE key = 'automation_webhook_key' LIMIT 1;
  IF _key IS NULL THEN RAISE EXCEPTION 'automation_webhook_key not seeded'; END IF;
  RETURN _key;
END; $function$
;

CREATE OR REPLACE FUNCTION public._log_billing_admin_action(_action text, _subscription_id uuid, _contact_id uuid, _details jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  INSERT INTO public.paige_audit_log (actor_id, action, entity_type, entity_id, tenant_id, details)
  VALUES (
    auth.uid(),
    _action,
    'tenant_service_subscription',
    _subscription_id,
    public.current_user_tenant_id(),
    COALESCE(_details, '{}'::jsonb) || jsonb_build_object('contact_id', _contact_id)
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public._ship26_assert_super_admin()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM public.user_roles
    WHERE user_id = auth.uid() AND role = 'super_admin'
  ) THEN
    RAISE EXCEPTION 'ship_26: super_admin required';
  END IF;
END;
$function$
;

