CREATE OR REPLACE FUNCTION public.accept_invitation(_token text, _user_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _invitation record;
  _token_hash text;
  _tenant_role public.tenant_role;
BEGIN
  _token_hash := encode(digest(_token, 'sha256'), 'hex');

  SELECT * INTO _invitation
  FROM public.invitations
  WHERE token_hash = _token_hash
    AND accepted_at IS NULL
    AND expires_at > now();

  IF _invitation IS NULL THEN
    RETURN json_build_object('success', false, 'message', 'Invalid or expired invitation');
  END IF;

  INSERT INTO public.user_roles (user_id, role)
  VALUES (_user_id, _invitation.role)
  ON CONFLICT (user_id, role) DO NOTHING;

  IF _invitation.tenant_id IS NOT NULL
     AND _invitation.role::text IN ('admin','coach','sales_rep','broker','broker_team_member','cs_rep','finance','viewer','moderator','user','client')
     AND _invitation.role <> 'super_admin'::public.app_role THEN
    _tenant_role := public.map_app_role_to_tenant_role(_invitation.role);

    INSERT INTO public.tenant_members (tenant_id, user_id, role, status, invited_at, joined_at)
    VALUES (_invitation.tenant_id, _user_id, _tenant_role, 'active', _invitation.created_at, now())
    ON CONFLICT (tenant_id, user_id) DO UPDATE
      SET role = CASE
            WHEN public.tenant_members.role = 'owner'::public.tenant_role THEN public.tenant_members.role
            WHEN EXCLUDED.role = 'admin'::public.tenant_role THEN 'admin'::public.tenant_role
            WHEN EXCLUDED.role = 'coach'::public.tenant_role
                 AND public.tenant_members.role NOT IN ('admin'::public.tenant_role, 'owner'::public.tenant_role)
              THEN 'coach'::public.tenant_role
            ELSE public.tenant_members.role
          END,
          status = 'active',
          joined_at = COALESCE(public.tenant_members.joined_at, now()),
          updated_at = now();

    UPDATE public.profiles
       SET active_tenant_id = _invitation.tenant_id
     WHERE user_id = _user_id
       AND active_tenant_id IS NULL;
  END IF;

  UPDATE public.invitations
  SET accepted_at = now()
  WHERE id = _invitation.id;

  RETURN json_build_object(
    'success', true,
    'role', _invitation.role,
    'tenant_id', _invitation.tenant_id,
    'message', 'Invitation accepted successfully'
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.accept_tenant_invite(_token text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _uid uuid := auth.uid();
  _tok public.tenant_invite_tokens;
BEGIN
  IF _uid IS NULL THEN
    RAISE EXCEPTION 'must be signed in to accept an invite';
  END IF;

  SELECT * INTO _tok FROM public.tenant_invite_tokens WHERE token = _token FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'invite token not found';
  END IF;
  IF _tok.revoked_at IS NOT NULL THEN
    RAISE EXCEPTION 'invite has been revoked';
  END IF;
  IF _tok.expires_at <= now() THEN
    RAISE EXCEPTION 'invite has expired';
  END IF;
  IF _tok.max_uses IS NOT NULL AND _tok.uses >= _tok.max_uses THEN
    RAISE EXCEPTION 'invite has reached its usage limit';
  END IF;

  -- Idempotent membership upsert
  INSERT INTO public.tenant_members (tenant_id, user_id, role, status, accepted_at)
  VALUES (_tok.tenant_id, _uid, _tok.default_role, 'active', now())
  ON CONFLICT (tenant_id, user_id) DO UPDATE
    SET status = 'active',
        accepted_at = COALESCE(public.tenant_members.accepted_at, now()),
        updated_at = now();

  UPDATE public.tenant_invite_tokens
     SET uses = uses + 1,
         last_used_at = now()
   WHERE id = _tok.id;

  -- Set this tenant as the user's active workspace
  UPDATE public.profiles
     SET active_tenant_id = _tok.tenant_id
   WHERE user_id = _uid;

  RETURN _tok.tenant_id;
END $function$
;

CREATE OR REPLACE FUNCTION public.admin_bulk_assign_coach(_coach uuid, _client_ids uuid[])
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  caller uuid := auth.uid();
  updated int;
BEGIN
  IF caller IS NULL THEN RAISE EXCEPTION 'unauthenticated'; END IF;
  IF NOT (public.has_role(caller, 'admin') OR public.has_role(caller, 'owner')) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  IF NOT EXISTS (SELECT 1 FROM public.user_roles WHERE user_id = _coach AND role = 'coach') THEN
    RAISE EXCEPTION 'target_user_is_not_a_coach';
  END IF;

  UPDATE public.clients
     SET assigned_coach_user_id = _coach,
         updated_at = now()
   WHERE id = ANY(_client_ids);
  GET DIAGNOSTICS updated = ROW_COUNT;

  RETURN jsonb_build_object('ok', true, 'updated', updated);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_cancel_customer_subscription(_subscription_id uuid, _grace_period_days integer DEFAULT 0)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_tenant uuid := public.current_user_tenant_id(); v_contact uuid;
BEGIN
  PERFORM public._assert_billing_admin();
  IF _grace_period_days > 0 THEN
    UPDATE public.tenant_service_subscriptions
      SET cancel_at_period_end = true,
          current_period_end = COALESCE(current_period_end, now()) + make_interval(days => _grace_period_days),
          updated_at = now()
      WHERE id = _subscription_id AND tenant_id = v_tenant
      RETURNING end_customer_contact_id INTO v_contact;
  ELSE
    UPDATE public.tenant_service_subscriptions
      SET status = 'canceled', cancel_at_period_end = true, updated_at = now()
      WHERE id = _subscription_id AND tenant_id = v_tenant
      RETURNING end_customer_contact_id INTO v_contact;
  END IF;
  IF v_contact IS NULL THEN RAISE EXCEPTION 'subscription not found'; END IF;
  PERFORM public._log_billing_admin_action(
    'billing.subscription.cancel', _subscription_id, v_contact,
    jsonb_build_object('grace_period_days', _grace_period_days)
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_change_customer_subscription_price(_subscription_id uuid, _new_price_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_tenant uuid := public.current_user_tenant_id(); v_contact uuid; v_price public.tenant_prices%ROWTYPE; v_old uuid;
BEGIN
  PERFORM public._assert_billing_admin();
  SELECT * INTO v_price FROM public.tenant_prices WHERE id = _new_price_id AND tenant_id = v_tenant AND active = true;
  IF v_price.id IS NULL THEN RAISE EXCEPTION 'new price not found or inactive'; END IF;

  SELECT price_id, end_customer_contact_id INTO v_old, v_contact
    FROM public.tenant_service_subscriptions
    WHERE id = _subscription_id AND tenant_id = v_tenant;
  IF v_contact IS NULL THEN RAISE EXCEPTION 'subscription not found'; END IF;

  UPDATE public.tenant_service_subscriptions
    SET price_id = _new_price_id, product_id = v_price.product_id, updated_at = now()
    WHERE id = _subscription_id AND tenant_id = v_tenant;

  PERFORM public._log_billing_admin_action(
    'billing.subscription.change_price', _subscription_id, v_contact,
    jsonb_build_object('old_price_id', v_old, 'new_price_id', _new_price_id)
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_create_customer_subscription(_contact_id uuid, _price_id uuid, _billing_period text DEFAULT 'monthly'::text, _start_date timestamp with time zone DEFAULT now())
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_tenant uuid := public.current_user_tenant_id();
  v_price public.tenant_prices%ROWTYPE;
  v_sub_id uuid;
  v_existing uuid;
BEGIN
  PERFORM public._assert_billing_admin();

  SELECT * INTO v_price FROM public.tenant_prices WHERE id = _price_id AND tenant_id = v_tenant AND active = true;
  IF v_price.id IS NULL THEN RAISE EXCEPTION 'price not found or not active for this tenant'; END IF;

  -- Duplicate prevention: no active sub per (tenant, contact, product)
  SELECT id INTO v_existing FROM public.tenant_service_subscriptions
   WHERE tenant_id = v_tenant AND end_customer_contact_id = _contact_id
     AND product_id = v_price.product_id AND status IN ('active','trialing','past_due','paused');
  IF v_existing IS NOT NULL THEN RAISE EXCEPTION 'customer already has an active subscription for this product'; END IF;

  INSERT INTO public.tenant_service_subscriptions (
    tenant_id, end_customer_contact_id, product_id, price_id,
    status, billing_period, current_period_start
  ) VALUES (
    v_tenant, _contact_id, v_price.product_id, _price_id,
    'active', _billing_period, _start_date
  ) RETURNING id INTO v_sub_id;

  PERFORM public._log_billing_admin_action(
    'billing.subscription.create', v_sub_id, _contact_id,
    jsonb_build_object('price_id', _price_id, 'billing_period', _billing_period)
  );
  RETURN v_sub_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_force_signout_user(target_user uuid)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
DECLARE
  removed integer := 0;
BEGIN
  IF target_user IS NULL THEN
    RAISE EXCEPTION 'target_user is required';
  END IF;

  DELETE FROM auth.refresh_tokens WHERE user_id::uuid = target_user;
  DELETE FROM auth.sessions WHERE user_id = target_user;
  GET DIAGNOSTICS removed = ROW_COUNT;
  RETURN removed;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_get_automation_webhook_url(_tenant_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE _cipher bytea; _plain text;
BEGIN
  IF NOT (public.is_platform_owner() OR public.is_tenant_admin(_tenant_id)) THEN
    RAISE EXCEPTION 'not authorized';
  END IF;
  SELECT automation_webhook_url_encrypted INTO _cipher FROM public.tenants WHERE id = _tenant_id;
  IF _cipher IS NULL THEN RETURN NULL; END IF;
  _plain := extensions.pgp_sym_decrypt(_cipher, public._automation_webhook_key());
  INSERT INTO public.pii_access_log (accessor_user_id, target_kind, target_id, field, purpose)
    VALUES (auth.uid(), 'tenant.automation_webhook_url', _tenant_id, 'automation_webhook_url', 'admin_read');
  RETURN _plain;
END; $function$
;

CREATE OR REPLACE FUNCTION public.admin_get_workflow_webhook_url(_workflow_id uuid)
 RETURNS text
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT n8n_webhook_url
  FROM public.paige_workflow_registry
  WHERE id = _workflow_id
    AND has_role(auth.uid(), 'admin'::app_role)
    AND (tenant_id IS NULL OR tenant_id = current_user_tenant_id());
$function$
;

CREATE OR REPLACE FUNCTION public.admin_get_workflow_webhook_url(_workflow_slug text)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE ct bytea;
BEGIN
  IF NOT (public.has_role(auth.uid(),'admin'::app_role) OR public.is_platform_owner(auth.uid())) THEN
    RAISE EXCEPTION 'not authorized';
  END IF;
  SELECT n8n_webhook_url_ct INTO ct FROM public.paige_workflow_registry
    WHERE workflow_slug = _workflow_slug LIMIT 1;
  RETURN public.platform_decrypt(ct);
END; $function$
;

CREATE OR REPLACE FUNCTION public.admin_meta_capi_token_is_set()
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NOT public.has_role(auth.uid(), 'admin'::app_role) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  RETURN EXISTS (SELECT 1 FROM public._internal_secrets WHERE key = 'meta_capi_access_token' AND length(coalesce(value,'')) > 0);
END $function$
;

CREATE OR REPLACE FUNCTION public.admin_metering_dead_letter_summary()
 RETURNS TABLE(event_type text, status text, row_count bigint, dollars_at_risk numeric, oldest_failure timestamp with time zone, most_recent_failure timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''
AS $function$
BEGIN
  IF NOT (public.has_role(auth.uid(), 'admin'::app_role)
       OR public.has_role(auth.uid(), 'super_admin'::app_role)) THEN
    RAISE EXCEPTION 'not_authorized';
  END IF;

  RETURN QUERY
  SELECT
    d.event_type,
    d.status,
    COUNT(*)::bigint,
    ROUND(SUM(COALESCE(d.quantity,1) * COALESCE(d.unit_amount_cents,0))::numeric / 100.0, 2),
    MIN(d.first_failed_at),
    MAX(d.last_failed_at)
  FROM public.platform_metered_events_dead_letter d
  GROUP BY d.event_type, d.status
  ORDER BY d.status, d.event_type;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_pause_customer_subscription(_subscription_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_tenant uuid := public.current_user_tenant_id(); v_contact uuid;
BEGIN
  PERFORM public._assert_billing_admin();
  UPDATE public.tenant_service_subscriptions
    SET status = 'paused', updated_at = now()
    WHERE id = _subscription_id AND tenant_id = v_tenant
    RETURNING end_customer_contact_id INTO v_contact;
  IF v_contact IS NULL THEN RAISE EXCEPTION 'subscription not found'; END IF;
  PERFORM public._log_billing_admin_action('billing.subscription.pause', _subscription_id, v_contact, '{}'::jsonb);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_propose_paige_actions(p_contact_id uuid, p_actions jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_tenant uuid;
  v_contact_tenant uuid;
  v_client_user uuid;
  v_consent boolean;
  v_action jsonb;
  v_ids uuid[] := ARRAY[]::uuid[];
  v_new_id uuid;
BEGIN
  IF v_uid IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'UNAUTHENTICATED');
  END IF;
  IF p_contact_id IS NULL OR p_actions IS NULL OR jsonb_typeof(p_actions) <> 'array' THEN
    RETURN jsonb_build_object('ok', false, 'error', 'INVALID_INPUT');
  END IF;

  v_tenant := public.current_user_tenant_id();
  IF v_tenant IS NULL AND NOT public.is_platform_owner() THEN
    RETURN jsonb_build_object('ok', false, 'error', 'NO_TENANT');
  END IF;

  SELECT c.tenant_id, c.linked_user_id, c.paige_shared_context_consent
    INTO v_contact_tenant, v_client_user, v_consent
  FROM public.clients c WHERE c.id = p_contact_id;

  IF v_contact_tenant IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'CONTACT_NOT_FOUND');
  END IF;
  IF NOT public.is_platform_owner() AND v_contact_tenant <> v_tenant THEN
    RETURN jsonb_build_object('ok', false, 'error', 'CROSS_TENANT_FORBIDDEN');
  END IF;

  IF NOT (
    public.has_role(v_uid,'admin'::public.app_role)
    OR public.has_role(v_uid,'super_admin'::public.app_role)
    OR public.has_role(v_uid,'coach'::public.app_role)
    OR public.is_platform_owner()
  ) THEN
    RETURN jsonb_build_object('ok', false, 'error', 'FORBIDDEN');
  END IF;

  IF NOT v_consent THEN
    RETURN jsonb_build_object('ok', false, 'error', 'CONSENT_NOT_GRANTED',
      'message', 'Customer has not consented to Paige-brokered actions.');
  END IF;

  FOR v_action IN SELECT * FROM jsonb_array_elements(p_actions)
  LOOP
    INSERT INTO public.paige_customer_actions(
      tenant_id, contact_id, initiated_by_admin_id,
      action_type, title, body, payload_json, status
    ) VALUES (
      v_contact_tenant, p_contact_id, v_uid,
      COALESCE(v_action->>'action_type','recommendation'),
      COALESCE(v_action->>'title','Recommendation'),
      NULLIF(v_action->>'body',''),
      COALESCE(v_action->'payload','{}'::jsonb),
      'customer_notified'
    ) RETURNING id INTO v_new_id;
    v_ids := array_append(v_ids, v_new_id);

    IF v_client_user IS NOT NULL THEN
      INSERT INTO public.notifications(user_id, type, title, message, action_url, metadata)
      VALUES (
        v_client_user, 'system'::public.notification_type,
        'Your coach shared a new step',
        COALESCE(v_action->>'title','New recommendation from your coach'),
        '/workspace/paige/actions',
        jsonb_build_object('source','paige_customer_action','action_id', v_new_id)
      );
    END IF;
  END LOOP;

  INSERT INTO public.paige_audit_log(actor_user_id, tenant_id, action, target_type, target_id, payload)
  VALUES (
    v_uid, v_contact_tenant, 'admin_propose_paige_actions', 'paige_customer_action', p_contact_id,
    jsonb_build_object('count', array_length(v_ids,1), 'ids', v_ids)
  );

  RETURN jsonb_build_object('ok', true, 'count', array_length(v_ids,1), 'ids', v_ids);
END; $function$
;

CREATE OR REPLACE FUNCTION public.admin_remove_coach_role(_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  caller uuid := auth.uid();
  active_count int;
BEGIN
  IF caller IS NULL THEN
    RAISE EXCEPTION 'unauthenticated';
  END IF;
  IF NOT (public.has_role(caller, 'admin') OR public.has_role(caller, 'owner')) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  SELECT count(*) INTO active_count
  FROM public.clients
  WHERE assigned_coach_user_id = _user_id
    AND coalesce(status, 'active') = 'active';

  IF active_count > 0 THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'active_clients', 'active_count', active_count);
  END IF;

  DELETE FROM public.user_roles WHERE user_id = _user_id AND role = 'coach';
  RETURN jsonb_build_object('ok', true);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_resume_customer_subscription(_subscription_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_tenant uuid := public.current_user_tenant_id(); v_contact uuid;
BEGIN
  PERFORM public._assert_billing_admin();
  UPDATE public.tenant_service_subscriptions
    SET status = 'active', updated_at = now()
    WHERE id = _subscription_id AND tenant_id = v_tenant AND status = 'paused'
    RETURNING end_customer_contact_id INTO v_contact;
  IF v_contact IS NULL THEN RAISE EXCEPTION 'subscription not found or not paused'; END IF;
  PERFORM public._log_billing_admin_action('billing.subscription.resume', _subscription_id, v_contact, '{}'::jsonb);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_set_automation_webhook_url(_tenant_id uuid, _url text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
BEGIN
  IF NOT (public.is_platform_owner() OR public.is_tenant_admin(_tenant_id)) THEN
    RAISE EXCEPTION 'not authorized';
  END IF;
  IF _url IS NULL OR length(trim(_url)) = 0 THEN
    UPDATE public.tenants SET automation_webhook_url_encrypted = NULL WHERE id = _tenant_id;
  ELSE
    IF _url NOT ILIKE 'https://%' THEN RAISE EXCEPTION 'webhook URL must be https://'; END IF;
    UPDATE public.tenants
      SET automation_webhook_url_encrypted = extensions.pgp_sym_encrypt(_url, public._automation_webhook_key())
      WHERE id = _tenant_id;
  END IF;
  INSERT INTO public.pii_access_log (accessor_user_id, target_kind, target_id, field, purpose)
    VALUES (auth.uid(), 'tenant.automation_webhook_url', _tenant_id, 'automation_webhook_url', 'admin_write');
END; $function$
;

CREATE OR REPLACE FUNCTION public.admin_set_meta_capi_token(_token text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NOT public.has_role(auth.uid(), 'admin'::app_role) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  IF _token IS NULL OR length(btrim(_token)) = 0 THEN
    DELETE FROM public._internal_secrets WHERE key = 'meta_capi_access_token';
  ELSE
    INSERT INTO public._internal_secrets (key, value)
    VALUES ('meta_capi_access_token', _token)
    ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = now();
  END IF;

  INSERT INTO public.paige_audit_log (actor_user_id, action, target_type, target_id, metadata)
  VALUES (auth.uid(), 'admin_set_meta_capi_token', 'paige_config', NULL,
          jsonb_build_object('cleared', _token IS NULL OR length(btrim(coalesce(_token,'')))=0));
END $function$
;

CREATE OR REPLACE FUNCTION public.admin_set_user_business_limit(_target_user_id uuid, _max_businesses integer)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _new_row public.user_business_limits%ROWTYPE;
BEGIN
  IF NOT public.has_role(auth.uid(), 'admin'::public.app_role) THEN
    RAISE EXCEPTION 'Unauthorized: admin role required';
  END IF;

  IF _max_businesses IS NULL OR _max_businesses < 1 THEN
    RAISE EXCEPTION 'max_businesses must be >= 1';
  END IF;

  INSERT INTO public.user_business_limits (user_id, max_businesses)
  VALUES (_target_user_id, _max_businesses)
  ON CONFLICT (user_id) DO UPDATE
    SET max_businesses = EXCLUDED.max_businesses,
        updated_at = now()
  RETURNING * INTO _new_row;

  INSERT INTO public.audit_logs (user_id, entity, action, entity_id, data)
  VALUES (
    auth.uid(),
    'user_business_limits',
    'admin_set_max_businesses',
    _target_user_id,
    jsonb_build_object('max_businesses', _max_businesses, 'target_user_id', _target_user_id::text)
  );

  RETURN json_build_object(
    'success', true,
    'user_id', _new_row.user_id,
    'max_businesses', _new_row.max_businesses,
    'additional_businesses_count', _new_row.additional_businesses_count
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.allocate_account_number(_tenant_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE _prefix text; _next bigint;
BEGIN
  SELECT account_number_prefix INTO _prefix FROM public.tenants WHERE id = _tenant_id;
  IF _prefix IS NULL THEN _prefix := 'ACCT'; END IF;
  INSERT INTO public.tenant_account_number_seq(tenant_id, last_value) VALUES (_tenant_id, 1)
  ON CONFLICT (tenant_id) DO UPDATE
    SET last_value = tenant_account_number_seq.last_value + 1, updated_at = now()
  RETURNING last_value INTO _next;
  RETURN _prefix || '-' || LPAD(_next::text, 6, '0');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.apply_approval_policy()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  pol record;
BEGIN
  IF NEW.category IS NULL THEN
    NEW.category := COALESCE(NEW.type, 'other');
  END IF;

  SELECT * INTO pol
  FROM public.paige_approval_policies
  WHERE active = true
    AND category = NEW.category
    AND (tenant_id IS NULL OR tenant_id = NEW.tenant_id)
  ORDER BY tenant_id NULLS LAST, created_at ASC
  LIMIT 1;

  IF pol.id IS NOT NULL THEN
    IF NEW.requires_role IS NULL      THEN NEW.requires_role := pol.requires_role; END IF;
    IF NEW.priority IS NULL OR NEW.priority = 3 THEN NEW.priority := pol.priority; END IF;
    IF NEW.risk_level IS NULL         THEN NEW.risk_level := pol.risk_level; END IF;
    IF NEW.sla_due_at IS NULL AND pol.sla_minutes IS NOT NULL THEN
      NEW.sla_due_at := now() + (pol.sla_minutes || ' minutes')::interval;
    END IF;
    IF NEW.assigned_to_user_id IS NULL AND pol.auto_assign_user_id IS NOT NULL THEN
      NEW.assigned_to_user_id := pol.auto_assign_user_id;
    END IF;
    IF (NEW.visible_to_roles IS NULL OR cardinality(NEW.visible_to_roles) = 0)
       AND pol.visible_to_roles IS NOT NULL THEN
      NEW.visible_to_roles := pol.visible_to_roles;
    END IF;
  END IF;

  -- Final fallback SLA so nothing sits forever.
  IF NEW.sla_due_at IS NULL THEN
    NEW.sla_due_at := now() + interval '48 hours';
  END IF;

  RETURN NEW;
END$function$
;

CREATE OR REPLACE FUNCTION public.apply_assignment_policy()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _policy public.paige_assignment_policy;
  _chosen uuid;
BEGIN
  IF NEW.tier IS NULL THEN RETURN NEW; END IF;

  SELECT * INTO _policy FROM public.paige_assignment_policy WHERE tier = NEW.tier;
  IF NOT FOUND OR _policy.strategy = 'manual'
     OR _policy.eligible_user_ids IS NULL
     OR array_length(_policy.eligible_user_ids, 1) IS NULL THEN
    RETURN NEW;
  END IF;

  IF EXISTS (
    SELECT 1 FROM public.paige_coach_assignments
    WHERE contact_id = NEW.id AND assigned_role = _policy.target_role AND active = true
  ) THEN RETURN NEW; END IF;

  SELECT u INTO _chosen
  FROM unnest(_policy.eligible_user_ids) AS u
  LEFT JOIN public.paige_coach_assignments a
    ON a.rep_user_id = u AND a.assigned_role = _policy.target_role AND a.active = true
  GROUP BY u
  ORDER BY count(a.id) ASC, random()
  LIMIT 1;

  IF _chosen IS NULL THEN RETURN NEW; END IF;

  INSERT INTO public.paige_coach_assignments
    (contact_id, assigned_role, rep_user_id, active, metadata)
  VALUES
    (NEW.id, _policy.target_role, _chosen, true,
     jsonb_build_object('source', _policy.strategy))
  ON CONFLICT (contact_id, assigned_role) WHERE active = true DO NOTHING;

  RETURN NEW;
END $function$
;

CREATE OR REPLACE FUNCTION public.approve_affiliate_application(_application_id uuid, _tier_key text DEFAULT NULL::text, _notes text DEFAULT NULL::text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _app          public.affiliate_applications%ROWTYPE;
  _tier_id      uuid;
  _final_tier   text;
  _matched_user uuid;
  _code         text;
  _affiliate_id uuid;
  _name_seed    text;
BEGIN
  IF NOT public.has_role(auth.uid(), 'admin'::public.app_role) THEN
    RAISE EXCEPTION 'Unauthorized: admin role required';
  END IF;

  SELECT * INTO _app FROM public.affiliate_applications WHERE id = _application_id;
  IF _app.id IS NULL THEN
    RAISE EXCEPTION 'Application not found';
  END IF;
  IF _app.status <> 'pending' THEN
    RAISE EXCEPTION 'Application is not pending (current status: %)', _app.status;
  END IF;

  _final_tier := COALESCE(_tier_key, _app.requested_tier_key, 'external');

  SELECT id INTO _tier_id
  FROM public.affiliate_commission_tiers
  WHERE tier_key = _final_tier
  LIMIT 1;
  IF _tier_id IS NULL THEN
    RAISE EXCEPTION 'Unknown commission tier: %', _final_tier;
  END IF;

  -- Try to match application to an existing auth user by email
  _matched_user := _app.user_id;
  IF _matched_user IS NULL THEN
    SELECT id INTO _matched_user
    FROM auth.users
    WHERE lower(email) = lower(_app.email)
    LIMIT 1;
  END IF;

  -- If user already has an affiliate profile, just link the application
  IF _matched_user IS NOT NULL THEN
    SELECT id INTO _affiliate_id
    FROM public.affiliate_profiles
    WHERE user_id = _matched_user
    LIMIT 1;
  END IF;

  -- Otherwise create a new affiliate profile
  IF _affiliate_id IS NULL THEN
    IF _matched_user IS NULL THEN
      RAISE EXCEPTION 'Cannot approve: applicant has no account yet. Ask them to sign up at the email %s first, then re-approve.', _app.email;
    END IF;

    -- Generate a unique referral code (mirrors auto_enroll_affiliate logic)
    _name_seed := COALESCE(
      NULLIF(regexp_replace(_app.full_name, '[^a-zA-Z0-9]', '', 'g'), ''),
      'PAIGE'
    );
    _code := upper(substr(_name_seed, 1, 4))
          || upper(substr(md5(random()::text || _matched_user::text), 1, 4));

    FOR i IN 1..5 LOOP
      EXIT WHEN NOT EXISTS (SELECT 1 FROM public.referral_codes WHERE code = _code);
      _code := upper(substr(_name_seed, 1, 4))
            || upper(substr(md5(random()::text || clock_timestamp()::text), 1, 4));
    END LOOP;

    INSERT INTO public.affiliate_profiles
      (user_id, referral_code, commission_tier_id, enrolled_from, active)
    VALUES
      (_matched_user, _code, _tier_id, 'application_' || _final_tier, true)
    RETURNING id INTO _affiliate_id;

    INSERT INTO public.referral_codes (code, affiliate_id, active)
    VALUES (_code, _affiliate_id, true)
    ON CONFLICT (code) DO NOTHING;
  END IF;

  -- Mark application approved
  UPDATE public.affiliate_applications
  SET status = 'approved',
      reviewed_by = auth.uid(),
      reviewed_at = now(),
      review_notes = _notes,
      resulting_affiliate_id = _affiliate_id,
      user_id = COALESCE(user_id, _matched_user)
  WHERE id = _application_id;

  RETURN json_build_object(
    'success', true,
    'affiliate_id', _affiliate_id,
    'matched_user_id', _matched_user
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.assign_client_account_number()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.account_number IS NULL AND NEW.tenant_id IS NOT NULL THEN
    NEW.account_number := public.allocate_account_number(NEW.tenant_id);
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.assignment_role_for(_role app_role)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public'
AS $function$
  SELECT CASE _role
    WHEN 'sales_rep'::app_role THEN 'lead_owner'
    WHEN 'cs_rep'::app_role    THEN 'cs_primary'
    WHEN 'coach'::app_role     THEN 'coach'
    ELSE NULL
  END
$function$
;

CREATE OR REPLACE FUNCTION public.attribute_conversion(p_user_id uuid, p_stripe_customer_id text, p_stripe_sub_id text, p_amount_cents integer, p_event_type text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_referral_code      text;
  v_affiliate_id       uuid;
  v_commission_rate    numeric;
  v_duration_months    integer;
  v_first_converted_at timestamptz;
  v_commission_cents   integer;
  v_eligible           boolean := true;
  v_conv_id            uuid;
begin
  select referral_code into v_referral_code
    from public.profiles
   where user_id = p_user_id and referral_code is not null
   limit 1;

  if v_referral_code is null then
    select referral_code into v_referral_code
      from public.referral_clicks
     where clicked_at >= now() - interval '60 days'
     order by clicked_at desc
     limit 1;
  end if;

  if v_referral_code is null then return null; end if;

  select ap.id, t.commission_rate, t.duration_months
    into v_affiliate_id, v_commission_rate, v_duration_months
    from public.affiliate_profiles ap
    join public.referral_codes rc on rc.affiliate_id = ap.id
    join public.affiliate_commission_tiers t on t.id = ap.commission_tier_id
   where rc.code = v_referral_code
     and ap.active = true
     and rc.active = true
   limit 1;

  if v_affiliate_id is null then return null; end if;

  if v_duration_months is not null and p_event_type = 'recurring' then
    select min(converted_at) into v_first_converted_at
      from public.referral_conversions
     where referred_user_id = p_user_id and affiliate_id = v_affiliate_id;

    if v_first_converted_at is not null
       and v_first_converted_at < now() - (v_duration_months || ' months')::interval
    then
      v_eligible := false;
    end if;
  end if;

  v_commission_cents := case
    when v_eligible then round(p_amount_cents * v_commission_rate)::integer
    else 0
  end;

  insert into public.referral_conversions (
    affiliate_id, referred_user_id, referral_code,
    stripe_customer_id, stripe_subscription_id,
    amount_cents, commission_cents, status, converted_at
  ) values (
    v_affiliate_id, p_user_id, v_referral_code,
    p_stripe_customer_id, p_stripe_sub_id,
    p_amount_cents, v_commission_cents,
    case when v_eligible then 'attributed' else 'expired' end,
    now()
  ) returning id into v_conv_id;

  return v_conv_id;
end $function$
;

CREATE OR REPLACE FUNCTION public.auto_advance_journey_on_tier()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _client_id uuid;
  _current_stage integer;
  _new_tier text;
BEGIN
  _new_tier := lower(COALESCE(NEW.tier, ''));
  IF _new_tier NOT IN ('standard','premium','vip') THEN
    RETURN NEW;
  END IF;

  SELECT id, journey_stage_id INTO _client_id, _current_stage
  FROM public.clients
  WHERE linked_user_id = NEW.user_id
  ORDER BY created_at ASC
  LIMIT 1;

  IF _client_id IS NULL THEN
    RETURN NEW;
  END IF;

  IF COALESCE(_current_stage, 0) < 3 THEN
    UPDATE public.clients
       SET journey_stage_id = 3,
           journey_stage_entered_at = now()
     WHERE id = _client_id;

    INSERT INTO public.paige_journey_stage_transitions
      (contact_id, from_stage_id, to_stage_id, source_event, metadata)
    VALUES
      (_client_id, _current_stage, 3, 'tier_upgrade',
       jsonb_build_object('tier', _new_tier));
  END IF;

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'auto_advance_journey_on_tier failed: %', SQLERRM;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.auto_assign_on_mirror()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_role text;
BEGIN
  IF NEW.mirror_source IS DISTINCT FROM 'mma_os' THEN RETURN NEW; END IF;
  IF NEW.tier IN ('premium','vip','internal','staff') THEN
    v_role := 'cs_primary';
  ELSE
    RETURN NEW;
  END IF;
  IF NOT EXISTS (
    SELECT 1 FROM public.paige_coach_assignments
    WHERE contact_id = NEW.id AND assigned_role = v_role AND active = true
  ) THEN
    INSERT INTO public.paige_coach_assignments (contact_id, assigned_role, rep_user_id, active, metadata)
    VALUES (NEW.id, v_role, NULL, true, jsonb_build_object('auto', true, 'reason', 'mirror_from_mma_os'));
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.auto_enroll_affiliate()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_tier_id uuid;
  v_code    text;
  v_role    text;
  v_aff_id  uuid;
begin
  v_role := new.role::text;
  if v_role not in ('admin','coach') then return new; end if;

  if exists (select 1 from public.affiliate_profiles where user_id = new.user_id) then
    return new;
  end if;

  select id into v_tier_id
    from public.affiliate_commission_tiers
   where tier_key = case when v_role = 'admin' then 'admin' else 'coach' end
   limit 1;

  v_code := upper(
    substr(
      coalesce(
        regexp_replace(
          (select full_name from public.profiles where user_id = new.user_id),
          '[^a-zA-Z0-9]', '', 'g'
        ),
        'PAIGE'
      ), 1, 4)
  ) || upper(substr(md5(random()::text || new.user_id::text), 1, 4));

  for i in 1..5 loop
    exit when not exists (select 1 from public.referral_codes where code = v_code);
    v_code := substr(v_code, 1, 4)
            || upper(substr(md5(random()::text || clock_timestamp()::text), 1, 4));
  end loop;

  insert into public.affiliate_profiles
    (user_id, referral_code, commission_tier_id, enrolled_from, active)
  values
    (new.user_id, v_code, v_tier_id, 'auto_' || v_role, true)
  returning id into v_aff_id;

  insert into public.referral_codes (code, affiliate_id, active)
  values (v_code, v_aff_id, true)
  on conflict (code) do nothing;

  return new;
end $function$
;

CREATE OR REPLACE FUNCTION public.auto_stub_business_from_contact()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _existing_business_id uuid;
  _new_business_id uuid;
  _trimmed_name text;
  _owner_user_id uuid;
BEGIN
  _trimmed_name := NULLIF(btrim(COALESCE(NEW.entity_name, '')), '');
  IF _trimmed_name IS NULL THEN
    RETURN NEW;
  END IF;
  IF NEW.primary_business_id IS NOT NULL THEN
    RETURN NEW;
  END IF;

  -- Prefer linked_user_id if it points to a real auth user, else fall back to created_by.
  IF NEW.linked_user_id IS NOT NULL
     AND EXISTS (SELECT 1 FROM auth.users WHERE id = NEW.linked_user_id) THEN
    _owner_user_id := NEW.linked_user_id;
  ELSIF NEW.created_by IS NOT NULL
        AND EXISTS (SELECT 1 FROM auth.users WHERE id = NEW.created_by) THEN
    _owner_user_id := NEW.created_by;
  ELSE
    RETURN NEW;
  END IF;

  -- Reuse an existing business owned by the same owner if one exists (only when
  -- the owner is the contact's linked_user — never auto-attach to a coach/creator's
  -- other portfolio companies).
  IF _owner_user_id = NEW.linked_user_id THEN
    SELECT id INTO _existing_business_id
      FROM public.businesses
     WHERE owner_user_id = _owner_user_id
     ORDER BY COALESCE(is_primary, false) DESC, created_at ASC
     LIMIT 1;

    IF _existing_business_id IS NOT NULL THEN
      UPDATE public.clients
         SET primary_business_id = _existing_business_id, updated_at = now()
       WHERE id = NEW.id AND primary_business_id IS NULL;
      RETURN NEW;
    END IF;
  END IF;

  INSERT INTO public.businesses (
    owner_user_id, legal_name, entity_type, is_primary, is_active,
    organizational_level, display_order
  ) VALUES (
    _owner_user_id, _trimmed_name, NEW.entity_type::entity_type,
    true, true, 0, 0
  )
  RETURNING id INTO _new_business_id;

  UPDATE public.clients
     SET primary_business_id = _new_business_id, updated_at = now()
   WHERE id = NEW.id AND primary_business_id IS NULL;

  BEGIN
    INSERT INTO public.paige_audit_log (actor_user_id, action, target_type, target_id, metadata)
    VALUES (NULL, 'auto_stub_business_from_contact', 'business', _new_business_id,
            jsonb_build_object(
              'contact_id', NEW.id,
              'owner_user_id', _owner_user_id,
              'owner_source', CASE WHEN _owner_user_id = NEW.linked_user_id THEN 'linked_user_id' ELSE 'created_by_fallback' END,
              'legal_name', _trimmed_name,
              'trigger_op', TG_OP
            ));
  EXCEPTION WHEN OTHERS THEN NULL;
  END;

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'auto_stub_business_from_contact failed for contact %: %', NEW.id, SQLERRM;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.can_access_contact(_user_id uuid, _contact_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT
    public.has_any_role(_user_id, ARRAY['admin','super_admin'])
    OR EXISTS (
      SELECT 1 FROM public.clients c
      WHERE c.id = _contact_id
        AND (
          c.lead_owner_user_id = _user_id
          OR c.cs_primary_user_id = _user_id
          OR c.assigned_coach_user_id = _user_id
          OR c.linked_user_id = _user_id
        )
    )
    OR EXISTS (
      SELECT 1 FROM public.paige_coach_assignments a
      WHERE a.contact_id = _contact_id
        AND a.active = true
        AND a.rep_user_id = _user_id
    );
$function$
;

CREATE OR REPLACE FUNCTION public.change_user_role(_target_user_id uuid, _from_role app_role, _to_role app_role, _tenant_id uuid DEFAULT NULL::uuid, _reason text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _caller uuid := auth.uid();
  _resolved_tenant uuid;
  _is_owner_call boolean := public.is_platform_owner();
  _is_admin_call boolean;
  _target_is_owner boolean;
  _tenant_role public.tenant_role;
  _protected public.app_role[] := ARRAY['admin','super_admin','platform_admin']::public.app_role[];
BEGIN
  IF _caller IS NULL THEN
    RAISE EXCEPTION 'ROLE_CHANGE_UNAUTHENTICATED' USING ERRCODE = '42501';
  END IF;

  _resolved_tenant := COALESCE(_tenant_id, public.current_user_tenant_id());
  IF _resolved_tenant IS NULL THEN
    RAISE EXCEPTION 'ROLE_CHANGE_NO_TENANT' USING ERRCODE = '22023';
  END IF;

  _is_admin_call := public.is_tenant_admin(_resolved_tenant) OR public.has_role(_caller, 'admin'::public.app_role);

  IF NOT (_is_owner_call OR _is_admin_call) THEN
    RAISE EXCEPTION 'ROLE_CHANGE_FORBIDDEN: admin privileges required' USING ERRCODE = '42501';
  END IF;

  IF NOT _is_owner_call AND (_from_role = ANY(_protected) OR _to_role = ANY(_protected)) THEN
    RAISE EXCEPTION 'ROLE_CHANGE_FORBIDDEN: cannot modify admin or super_admin (owner-only)'
      USING ERRCODE = '42501';
  END IF;

  IF _to_role = 'super_admin'::public.app_role THEN
    RAISE EXCEPTION 'ROLE_CHANGE_FORBIDDEN: super_admin is bootstrap-only' USING ERRCODE = '42501';
  END IF;

  SELECT EXISTS(
    SELECT 1 FROM public.tenants
     WHERE id = _resolved_tenant AND owner_user_id = _target_user_id
  ) INTO _target_is_owner;

  IF _target_is_owner AND _from_role = 'admin'::public.app_role THEN
    RAISE EXCEPTION 'ROLE_CHANGE_FORBIDDEN: tenant owner cannot be demoted from admin'
      USING ERRCODE = '42501';
  END IF;

  DELETE FROM public.user_roles WHERE user_id = _target_user_id AND role = _from_role;

  INSERT INTO public.user_roles (user_id, role)
  VALUES (_target_user_id, _to_role)
  ON CONFLICT (user_id, role) DO NOTHING;

  BEGIN
    _tenant_role := public.map_app_role_to_tenant_role(_to_role);
    INSERT INTO public.tenant_members (tenant_id, user_id, role, status, invited_at, joined_at)
    VALUES (_resolved_tenant, _target_user_id, _tenant_role, 'active', now(), now())
    ON CONFLICT (tenant_id, user_id) DO UPDATE
      SET role = EXCLUDED.role, status = 'active', updated_at = now()
      WHERE public.tenant_members.role <> 'owner'::public.tenant_role;
  EXCEPTION WHEN OTHERS THEN
    INSERT INTO public.paige_audit_log
      (actor_user_id, actor_role, action, target_type, target_id, payload, tenant_id)
    VALUES (
      _caller,
      CASE WHEN _is_owner_call THEN 'super_admin' ELSE 'admin' END,
      'role:change:mirror_failed', 'user_role', _target_user_id,
      jsonb_build_object(
        'from_role', _from_role,
        'to_role', _to_role,
        'tenant_id', _resolved_tenant,
        'error_message', SQLERRM,
        'error_code', SQLSTATE
      ),
      _resolved_tenant
    );
  END;

  INSERT INTO public.paige_audit_log
    (actor_user_id, actor_role, action, target_type, target_id, payload, tenant_id)
  VALUES (
    _caller,
    CASE WHEN _is_owner_call THEN 'super_admin' ELSE 'admin' END,
    'role:change', 'user_role', _target_user_id,
    jsonb_build_object('from_role', _from_role, 'to_role', _to_role,
                       'tenant_id', _resolved_tenant, 'reason', _reason),
    _resolved_tenant
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_feature_access(_user_id uuid, _feature text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _plan_slug TEXT;
  _is_complimentary BOOLEAN;
  _has_access BOOLEAN := false;
BEGIN
  -- Admins always get full access
  IF has_role(_user_id, 'admin'::app_role) THEN
    RETURN true;
  END IF;

  -- Coaches always get full access (staff bypass)
  IF has_role(_user_id, 'coach'::app_role) THEN
    RETURN true;
  END IF;

  -- Complimentary access flag = full Pro-level access, no Stripe required
  SELECT COALESCE(is_complimentary, false) INTO _is_complimentary
  FROM public.profiles
  WHERE user_id = _user_id
  LIMIT 1;

  IF _is_complimentary THEN
    RETURN true;
  END IF;

  -- Otherwise fall back to Stripe-backed plan
  SELECT us.plan_slug INTO _plan_slug
  FROM public.user_subscriptions us
  WHERE us.user_id = _user_id
  LIMIT 1;

  IF _plan_slug IS NULL THEN
    RETURN false;
  END IF;

  SELECT
    CASE _feature
      WHEN 'business_credit' THEN (sp.has_business_credit = true)
      WHEN 'funding_tools' THEN (sp.has_funding_tools = true)
      WHEN 'unlimited_disputes' THEN (sp.dispute_limit IS NULL)
      WHEN 'advanced_analytics' THEN (sp.slug IN ('premium', 'enterprise'))
      WHEN 'document_upload' THEN (sp.has_document_upload = true)
      WHEN 'personal_document_upload' THEN (sp.has_personal_document_upload = true)
      WHEN 'business_document_upload' THEN (sp.has_business_document_upload = true)
      ELSE false
    END INTO _has_access
  FROM public.subscription_plans sp
  WHERE sp.slug = _plan_slug;

  RETURN COALESCE(_has_access, false);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_rate_limit(_user_id uuid, _function_name text, _max_requests integer DEFAULT 30, _window_minutes integer DEFAULT 1)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _window_start timestamptz;
  _current_count int;
BEGIN
  -- Calculate window start time
  _window_start := date_trunc('minute', now()) - (EXTRACT(minute FROM now())::int % _window_minutes) * INTERVAL '1 minute';
  
  -- Get current count for this window
  SELECT request_count INTO _current_count
  FROM public.api_rate_limits
  WHERE user_id = _user_id
    AND function_name = _function_name
    AND window_start = _window_start;
  
  -- If no record exists, create one
  IF _current_count IS NULL THEN
    INSERT INTO public.api_rate_limits (user_id, function_name, request_count, window_start)
    VALUES (_user_id, _function_name, 1, _window_start);
    RETURN true;
  END IF;
  
  -- If limit exceeded, return false
  IF _current_count >= _max_requests THEN
    RETURN false;
  END IF;
  
  -- Increment counter
  UPDATE public.api_rate_limits
  SET request_count = request_count + 1
  WHERE user_id = _user_id
    AND function_name = _function_name
    AND window_start = _window_start;
  
  RETURN true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.claim_client(_client_id uuid)
 RETURNS paige_coach_assignments
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _uid uuid := auth.uid();
  _client_tier text;
  _role app_role;
  _assignment_role text;
  _pool text[];
  _row public.paige_coach_assignments;
BEGIN
  IF _uid IS NULL THEN RAISE EXCEPTION 'auth_required' USING ERRCODE = '42501'; END IF;

  IF public.has_role(_uid, 'sales_rep'::app_role) THEN
    _role := 'sales_rep'::app_role;
  ELSIF public.has_role(_uid, 'cs_rep'::app_role) THEN
    _role := 'cs_rep'::app_role;
  ELSE
    RAISE EXCEPTION 'role_not_eligible_to_claim' USING ERRCODE = '42501';
  END IF;

  _assignment_role := public.assignment_role_for(_role);
  _pool := public.tier_pool_for_role(_role);

  SELECT tier INTO _client_tier FROM public.clients WHERE id = _client_id;
  IF _client_tier IS NULL OR NOT (_client_tier = ANY(_pool)) THEN
    RAISE EXCEPTION 'client_not_in_pool' USING ERRCODE = '42501';
  END IF;

  INSERT INTO public.paige_coach_assignments
    (contact_id, assigned_role, rep_user_id, active, metadata)
  VALUES
    (_client_id, _assignment_role, _uid, true,
     jsonb_build_object('source','self_claim','claimed_at', now()))
  ON CONFLICT (contact_id, assigned_role) WHERE active = true DO NOTHING
  RETURNING * INTO _row;

  IF _row.id IS NULL THEN
    RAISE EXCEPTION 'claim_race_lost' USING ERRCODE = '40001';
  END IF;

  RETURN _row;
END $function$
;

CREATE OR REPLACE FUNCTION public.client_advance_onboarding_stage(p_to_stage text, p_payload jsonb DEFAULT '{}'::jsonb)
 RETURNS TABLE(client_id uuid, onboarding_stage text, updated_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id uuid := auth.uid();
  v_client  public.clients%ROWTYPE;
  v_order   text[] := ARRAY['pre_invite','invited','signing_agreement','accepting_payment','completing_intake','uploading_docs','completed'];
  v_from_idx int;
  v_to_idx   int;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'not_authenticated';
  END IF;

  IF NOT (p_to_stage = ANY (v_order)) THEN
    RAISE EXCEPTION 'invalid_stage: %', p_to_stage;
  END IF;

  SELECT * INTO v_client
  FROM public.clients
  WHERE linked_user_id = v_user_id
  ORDER BY updated_at DESC NULLS LAST
  LIMIT 1;

  IF v_client.id IS NULL THEN
    RAISE EXCEPTION 'no_linked_client';
  END IF;

  v_from_idx := COALESCE(array_position(v_order, COALESCE(v_client.onboarding_stage, 'invited')), 1);
  v_to_idx   := array_position(v_order, p_to_stage);

  IF v_to_idx > v_from_idx THEN
    UPDATE public.clients
       SET onboarding_stage = p_to_stage,
           updated_at = now()
     WHERE id = v_client.id;

    INSERT INTO public.paige_audit_log (actor_user_id, action, target_type, target_id, payload)
    VALUES (
      v_user_id,
      'onboarding_stage_advanced',
      'client',
      v_client.id,
      jsonb_build_object(
        'from_stage', v_client.onboarding_stage,
        'to_stage',   p_to_stage,
        'payload',    COALESCE(p_payload, '{}'::jsonb)
      )
    );
  END IF;

  RETURN QUERY
  SELECT c.id, c.onboarding_stage, c.updated_at
  FROM public.clients c
  WHERE c.id = v_client.id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.client_has_role_assigned(_client uuid, _assignment_role text)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM public.paige_coach_assignments
    WHERE contact_id = _client AND assigned_role = _assignment_role AND active = true
  )
$function$
;

CREATE OR REPLACE FUNCTION public.client_onboarding_status(p_contact_id uuid)
 RETURNS TABLE(contact_id uuid, linked_user_id uuid, invite_accepted_at timestamp with time zone, password_set_at timestamp with time zone, agreement_signed_at timestamp with time zone, intake_submitted_at timestamp with time zone, stage text, ready boolean)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller uuid := auth.uid();
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'not authenticated';
  END IF;

  IF NOT public.can_access_contact(v_caller, p_contact_id) THEN
    RAISE EXCEPTION 'not authorized for this contact';
  END IF;

  RETURN QUERY
  SELECT
    c.id,
    c.linked_user_id,
    -- invite acceptance = linkage timestamp (use updated_at fallback)
    CASE WHEN c.linked_user_id IS NOT NULL THEN COALESCE(u.email_confirmed_at, u.created_at) END,
    -- password set proxy: any successful sign-in
    u.last_sign_in_at,
    c.agreement_signed_at,
    c.onboarding_completed_at,
    c.onboarding_stage::text,
    (c.linked_user_id IS NOT NULL
      AND c.agreement_signed_at IS NOT NULL
      AND c.onboarding_stage = 'completed')
  FROM public.clients c
  LEFT JOIN auth.users u ON u.id = c.linked_user_id
  WHERE c.id = p_contact_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.client_view_ready(p_contact_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM public.clients c
    WHERE c.id = p_contact_id
      AND c.linked_user_id IS NOT NULL
      AND c.agreement_signed_at IS NOT NULL
      AND c.onboarding_stage = 'completed'
  );
$function$
;

CREATE OR REPLACE FUNCTION public.coach_can_access_user(_coach uuid, _user uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM public.coach_clients cc
    WHERE cc.coach_user_id = _coach AND cc.client_user_id = _user AND cc.status = 'active'
  ) OR EXISTS (
    SELECT 1
    FROM public.clients c
    WHERE c.linked_user_id = _user
      AND (
        c.assigned_coach_user_id = _coach
        OR EXISTS (
          SELECT 1 FROM public.paige_coach_assignments pca
          WHERE pca.contact_id = c.id AND pca.rep_user_id = _coach AND pca.active = true
        )
      )
  );
$function$
;

CREATE OR REPLACE FUNCTION public.compute_contact_readiness(_contact_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id uuid;
  v_stored  integer;
  v_owner   integer;
  v_biz     integer;
  v_cash    integer;
  v_bank    integer;
  v_sig     integer;
  v_count   integer := 0;
  v_sum     integer := 0;
BEGIN
  SELECT linked_user_id INTO v_user_id FROM public.clients WHERE id = _contact_id;

  -- Prefer stored composite if present
  IF v_user_id IS NOT NULL THEN
    SELECT overall_score INTO v_stored
      FROM public.funding_readiness_scores
     WHERE user_id = v_user_id
     ORDER BY last_calculated_at DESC NULLS LAST
     LIMIT 1;
    IF v_stored IS NOT NULL AND v_stored > 0 THEN
      RETURN LEAST(100, GREATEST(0, v_stored));
    END IF;
  END IF;

  -- Owner credit: map FICO 300-850 → 0-100
  SELECT GREATEST(0, LEAST(100, ROUND(((score::numeric - 300) / 550.0) * 100)))::int
    INTO v_owner
    FROM public._latest_owner_credit WHERE contact_id = _contact_id;
  IF v_owner IS NOT NULL THEN v_sum := v_sum + v_owner; v_count := v_count + 1; END IF;

  -- Business credit: average bureau scores in `scores` jsonb, normalize Paydex/Intelliscore (0-100 already)
  SELECT GREATEST(0, LEAST(100, ROUND(AVG((value)::numeric))))::int INTO v_biz
    FROM public.paige_business_credit_profiles,
         LATERAL jsonb_each_text(COALESCE(scores, '{}'::jsonb))
    WHERE contact_id = _contact_id AND value ~ '^[0-9]+(\.[0-9]+)?$';
  IF v_biz IS NOT NULL THEN v_sum := v_sum + v_biz; v_count := v_count + 1; END IF;

  -- Cash flow: use stored readiness score, else proxy from runway days
  SELECT COALESCE(funding_readiness_score,
                  LEAST(100, GREATEST(0, COALESCE(runway_days, 0))))
    INTO v_cash
    FROM public._latest_cash_flow WHERE contact_id = _contact_id;
  IF v_cash IS NOT NULL THEN v_sum := v_sum + v_cash; v_count := v_count + 1; END IF;

  -- Banking depth: 1 active connection = 60, 2 = 80, 3+ = 100
  SELECT CASE WHEN bank_connections_active >= 3 THEN 100
              WHEN bank_connections_active = 2 THEN 80
              WHEN bank_connections_active = 1 THEN 60
              ELSE NULL END
    INTO v_bank
    FROM public._bank_rollup WHERE contact_id = _contact_id;
  IF v_bank IS NOT NULL THEN v_sum := v_sum + v_bank; v_count := v_count + 1; END IF;

  -- Signature completion ratio
  SELECT CASE WHEN envelopes_total = 0 THEN NULL
              ELSE ROUND((envelopes_completed::numeric / envelopes_total) * 100)::int END
    INTO v_sig
    FROM public._signature_rollup WHERE contact_id = _contact_id;
  IF v_sig IS NOT NULL THEN v_sum := v_sum + v_sig; v_count := v_count + 1; END IF;

  IF v_count = 0 THEN RETURN NULL; END IF;
  RETURN ROUND(v_sum::numeric / v_count)::int;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_default_business_limit()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _plan text;
BEGIN
  SELECT plan_slug INTO _plan
  FROM public.user_subscriptions
  WHERE user_id = NEW.user_id
  LIMIT 1;

  INSERT INTO public.user_business_limits (user_id, max_businesses)
  VALUES (NEW.user_id, public.default_max_businesses_for_plan(_plan))
  ON CONFLICT (user_id) DO NOTHING;

  RETURN NEW;
END;
$function$
;

