CREATE OR REPLACE FUNCTION public.create_tenant_invite_token(_tenant_id uuid, _kind text DEFAULT 'consumer'::text, _default_role tenant_role DEFAULT 'member'::tenant_role, _expires_in_days integer DEFAULT 30, _max_uses integer DEFAULT NULL::integer)
 RETURNS tenant_invite_tokens
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _row public.tenant_invite_tokens;
  _new_token text;
BEGIN
  IF NOT (public.is_platform_owner() OR public.is_tenant_admin(_tenant_id)) THEN
    RAISE EXCEPTION 'not authorized to create invite tokens for this tenant';
  END IF;

  IF _kind NOT IN ('consumer','team') THEN
    RAISE EXCEPTION 'invalid invite kind: %', _kind;
  END IF;

  _new_token := encode(gen_random_bytes(24), 'base64');
  _new_token := replace(replace(replace(_new_token, '+', '-'), '/', '_'), '=', '');

  INSERT INTO public.tenant_invite_tokens
    (tenant_id, token, kind, default_role, created_by, expires_at, max_uses)
  VALUES
    (_tenant_id, _new_token, _kind, _default_role, auth.uid(),
     now() + make_interval(days => GREATEST(_expires_in_days, 1)),
     _max_uses)
  RETURNING * INTO _row;

  RETURN _row;
END $function$
;

CREATE OR REPLACE FUNCTION public.current_user_roles()
 RETURNS text[]
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT COALESCE(array_agg(role::text), ARRAY[]::text[])
  FROM public.user_roles WHERE user_id = auth.uid();
$function$
;

CREATE OR REPLACE FUNCTION public.current_user_tenant_id()
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT COALESCE(
    (SELECT active_tenant_id FROM public.profiles WHERE user_id = auth.uid()),
    (SELECT tenant_id FROM public.tenant_members
       WHERE user_id = auth.uid() AND status = 'active'
       ORDER BY joined_at ASC LIMIT 1)
  );
$function$
;

CREATE OR REPLACE FUNCTION public.customer_paige_activity_summary(p_days integer DEFAULT 7)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  v_contact_id uuid;
  v_count int;
  v_last timestamptz;
BEGIN
  SELECT id INTO v_contact_id FROM public.clients WHERE linked_user_id = auth.uid() LIMIT 1;
  IF v_contact_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'NO_LINKED_CONTACT');
  END IF;
  SELECT count(*), max(created_at) INTO v_count, v_last
  FROM public.paige_context_loads
  WHERE contact_id = v_contact_id
    AND consent_state = 'granted'
    AND created_at > now() - make_interval(days => p_days);
  RETURN jsonb_build_object('ok', true, 'window_days', p_days, 'count', v_count, 'last_at', v_last);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.customer_respond_to_action(p_action_id uuid, p_response_type text, p_response_text text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_action public.paige_customer_actions%ROWTYPE;
  v_owner uuid;
  v_new_status text;
BEGIN
  IF v_uid IS NULL THEN RETURN jsonb_build_object('ok', false, 'error', 'UNAUTHENTICATED'); END IF;
  IF p_response_type NOT IN ('accepted','declined','question','completed') THEN
    RETURN jsonb_build_object('ok', false, 'error', 'INVALID_RESPONSE_TYPE');
  END IF;

  SELECT * INTO v_action FROM public.paige_customer_actions WHERE id = p_action_id;
  IF NOT FOUND THEN RETURN jsonb_build_object('ok', false, 'error', 'ACTION_NOT_FOUND'); END IF;

  SELECT linked_user_id INTO v_owner FROM public.clients WHERE id = v_action.contact_id;
  IF v_owner IS NULL OR v_owner <> v_uid THEN
    RETURN jsonb_build_object('ok', false, 'error', 'FORBIDDEN');
  END IF;

  IF v_action.status = 'expired' OR v_action.expires_at < now() THEN
    RETURN jsonb_build_object('ok', false, 'error', 'ACTION_EXPIRED');
  END IF;

  INSERT INTO public.paige_customer_responses(
    action_id, contact_id, responded_by_user_id, response_type, response_text
  ) VALUES (
    p_action_id, v_action.contact_id, v_uid, p_response_type, NULLIF(p_response_text,'')
  );

  v_new_status := CASE p_response_type
    WHEN 'declined' THEN 'customer_declined'
    WHEN 'completed' THEN 'customer_acted'
    WHEN 'accepted' THEN 'customer_acted'
    ELSE v_action.status
  END;

  UPDATE public.paige_customer_actions
     SET status = v_new_status, updated_at = now()
   WHERE id = p_action_id;

  INSERT INTO public.notifications(user_id, type, title, message, action_url, metadata)
  VALUES (
    v_action.initiated_by_admin_id, 'system'::public.notification_type,
    'Client responded to your Paige action',
    COALESCE(v_action.title,'Action') || ' — ' || p_response_type,
    '/admin/contacts/' || v_action.contact_id::text,
    jsonb_build_object('source','paige_customer_response','action_id', p_action_id, 'response_type', p_response_type)
  );

  INSERT INTO public.paige_audit_log(actor_user_id, tenant_id, action, target_type, target_id, payload)
  VALUES (
    v_uid, v_action.tenant_id, 'customer_respond_to_action', 'paige_customer_action', p_action_id,
    jsonb_build_object('response_type', p_response_type, 'contact_id', v_action.contact_id)
  );

  RETURN jsonb_build_object('ok', true, 'status', v_new_status);
END; $function$
;

CREATE OR REPLACE FUNCTION public.default_max_businesses_for_plan(_plan_slug text)
 RETURNS integer
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public'
AS $function$
  SELECT CASE COALESCE(_plan_slug, 'free')
    WHEN 'free' THEN 1
    WHEN 'starter' THEN 1
    WHEN 'professional' THEN 3
    WHEN 'growth' THEN 3
    WHEN 'premium' THEN 999
    WHEN 'scale' THEN 999
    WHEN 'broker' THEN 999
    WHEN 'broker_workspace' THEN 999
    WHEN 'enterprise' THEN 999
    ELSE 1
  END
$function$
;

CREATE OR REPLACE FUNCTION public.delete_credit_report_upload(_upload_id uuid, _calling_user_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _upload record;
  _file_path text;
BEGIN
  IF NOT (public.has_role(_calling_user_id, 'admin') OR public.has_role(_calling_user_id, 'coach')) THEN
    RAISE EXCEPTION 'Unauthorized: only admins or coaches can delete uploads';
  END IF;

  SELECT id, file_path, user_id INTO _upload
  FROM public.credit_report_uploads
  WHERE id = _upload_id;

  IF _upload IS NULL THEN
    RETURN json_build_object('success', false, 'message', 'Upload not found');
  END IF;

  _file_path := _upload.file_path;

  DELETE FROM public.credit_report_personal_info
  WHERE credit_report_upload_id = _upload_id;

  DELETE FROM public.credit_report_uploads
  WHERE id = _upload_id;

  INSERT INTO public.audit_logs (user_id, entity, action, entity_id, data)
  VALUES (
    _calling_user_id,
    'credit_report_uploads',
    'admin_delete',
    _upload_id,
    jsonb_build_object('file_path', _file_path, 'target_user_id', _upload.user_id::text)
  );

  RETURN json_build_object(
    'success', true,
    'file_path', _file_path,
    'message', 'Upload and related data deleted'
  );
END;
$function$
;

