CREATE OR REPLACE FUNCTION public.enforce_doctrine_120_columns()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  rec record;
  existing text[];
  missing text[];
  drift_count int := 0;
  results jsonb := '[]'::jsonb;
BEGIN
  FOR rec IN SELECT * FROM public.doctrine_120_canonical_columns LOOP
    SELECT array_agg(column_name::text)
      INTO existing
      FROM information_schema.columns
     WHERE table_schema = rec.table_schema
       AND table_name = rec.table_name;

    IF existing IS NULL THEN
      drift_count := drift_count + 1;
      results := results || jsonb_build_object(
        'domain', rec.domain,
        'status', 'MISSING_TABLE',
        'target', rec.table_schema || '.' || rec.table_name
      );
      CONTINUE;
    END IF;

    missing := ARRAY(
      SELECT unnest(rec.canonical_columns)
      EXCEPT
      SELECT unnest(existing)
    );

    IF array_length(missing, 1) IS NOT NULL THEN
      drift_count := drift_count + 1;
      results := results || jsonb_build_object(
        'domain', rec.domain,
        'status', 'DRIFT',
        'target', rec.table_schema || '.' || rec.table_name,
        'missing_columns', missing
      );
    ELSE
      results := results || jsonb_build_object('domain', rec.domain, 'status', 'OK');
    END IF;
  END LOOP;

  IF drift_count > 0 THEN
    INSERT INTO public.paige_admin_notifications (kind, severity, title, body, metadata)
    VALUES (
      'doctrine_120_column_drift',
      'high',
      'Doctrine §120 column drift detected',
      'One or more canonical column names are missing from their target tables. Code referencing them will fail at runtime.',
      jsonb_build_object('results', results, 'detected_at', now())
    );
  END IF;

  RETURN jsonb_build_object('drift_count', drift_count, 'checked_at', now(), 'results', results);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.enforce_doctrine_120_full()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  enums_result jsonb;
  cols_result  jsonb;
BEGIN
  enums_result := public.enforce_doctrine_120();
  cols_result  := public.enforce_doctrine_120_columns();
  RETURN jsonb_build_object(
    'enums', enums_result,
    'columns', cols_result,
    'checked_at', now()
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.enforce_doctrine_120()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  rec record;
  constraint_def text;
  found_values text[];
  missing text[];
  extra text[];
  drift_count int := 0;
  results jsonb := '[]'::jsonb;
BEGIN
  FOR rec IN
    SELECT * FROM public.doctrine_120_canonical_enums
  LOOP
    SELECT pg_get_constraintdef(c.oid)
      INTO constraint_def
      FROM pg_constraint c
      JOIN pg_class t ON t.oid = c.conrelid
      JOIN pg_namespace n ON n.oid = t.relnamespace
     WHERE n.nspname = rec.constraint_schema
       AND t.relname = rec.constraint_table
       AND c.conname = rec.constraint_name
     LIMIT 1;

    IF constraint_def IS NULL THEN
      drift_count := drift_count + 1;
      results := results || jsonb_build_object(
        'domain', rec.domain,
        'status', 'MISSING_CONSTRAINT',
        'constraint', rec.constraint_schema || '.' || rec.constraint_table || '.' || rec.constraint_name
      );
      CONTINUE;
    END IF;

    -- Extract single-quoted literals from the CHECK definition
    SELECT array_agg(DISTINCT m[1] ORDER BY m[1])
      INTO found_values
      FROM regexp_matches(constraint_def, '''([a-z_]+)''', 'g') AS m;

    missing := ARRAY(SELECT unnest(rec.canonical_values) EXCEPT SELECT unnest(COALESCE(found_values, ARRAY[]::text[])));
    extra   := ARRAY(SELECT unnest(COALESCE(found_values, ARRAY[]::text[])) EXCEPT SELECT unnest(rec.canonical_values));

    IF array_length(missing, 1) IS NOT NULL OR array_length(extra, 1) IS NOT NULL THEN
      drift_count := drift_count + 1;
      results := results || jsonb_build_object(
        'domain', rec.domain,
        'status', 'DRIFT',
        'missing_from_db', COALESCE(missing, ARRAY[]::text[]),
        'extra_in_db', COALESCE(extra, ARRAY[]::text[])
      );
    ELSE
      results := results || jsonb_build_object('domain', rec.domain, 'status', 'OK');
    END IF;
  END LOOP;

  IF drift_count > 0 THEN
    INSERT INTO public.paige_admin_notifications (
      kind, severity, title, body, metadata
    ) VALUES (
      'doctrine_120_drift',
      'high',
      'Doctrine §120 drift detected',
      'One or more schema CHECK constraints have drifted from canonical enums. Review and align.',
      jsonb_build_object('results', results, 'detected_at', now())
    );
  END IF;

  RETURN jsonb_build_object('drift_count', drift_count, 'checked_at', now(), 'results', results);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.enforce_proposal_doctrine_120()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  canonical text[];
  payload text;
  legacy_labels text[] := ARRAY['lead','prospect','customer','active','churned','alumni','funded','paused'];
  hit text;
BEGIN
  SELECT canonical_values INTO canonical
    FROM public.doctrine_120_canonical_enums
   WHERE domain = 'lifecycle_stage';

  -- Concatenate row to text for a single regex sweep (proposals are small JSONB blobs)
  payload := lower(coalesce(row_to_json(NEW)::text, ''));

  -- Look for "lifecycle_stage": "<legacy>" patterns
  FOREACH hit IN ARRAY legacy_labels LOOP
    IF payload ~ ('"lifecycle_stage"\s*:\s*"' || hit || '"') AND NOT (hit = ANY(canonical)) THEN
      RAISE EXCEPTION 'Doctrine §120 violation: proposal references legacy lifecycle_stage "%". Use canonical §111 values: %', hit, array_to_string(canonical, ', ')
        USING ERRCODE = 'check_violation';
    END IF;
  END LOOP;

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.enforce_subagent_doctrine_116()
 RETURNS TABLE(out_slug text, out_action text, out_match text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  rec record;
  business_re text := '\m[A-Z][A-Za-z0-9&''-]+(\s+[A-Z][A-Za-z0-9&''-]+)*\s+(LLC|Inc|Corp|Corporation|Capital|Group|Holdings|Partners|Ventures|Bank|Financial)\M';
  -- Conservative first+last regex; allowlist filters common safe phrases.
  name_re text := '\m[A-Z][a-z]{2,}\s+[A-Z][a-z]{2,}\M';
  safe_allowlist text[] := ARRAY[
    'Mogul Maker','Maker Academy','Mogul Academy',
    'Paige Agent','Lovable Cloud','Lovable AI',
    'First Last','John Doe','Jane Doe',
    'United States','New York','Los Angeles'
  ];
  candidate text;
  matched text;
  already_notified boolean;
BEGIN
  FOR rec IN
    SELECT s.slug AS s_slug, s.name AS s_name, s.enabled AS s_enabled, s.system_prompt AS s_prompt
    FROM public.paige_subagents s
    WHERE s.system_prompt IS NOT NULL
  LOOP
    matched := NULL;

    -- Business suffix patterns first (high signal)
    candidate := substring(rec.s_prompt FROM business_re);
    IF candidate IS NOT NULL THEN
      matched := 'business_name:' || candidate;
    ELSE
      -- First+Last scan, filtering allowlist
      FOR candidate IN
        SELECT m[1] FROM regexp_matches(rec.s_prompt, name_re, 'g') AS m
      LOOP
        IF NOT (candidate = ANY(safe_allowlist)) THEN
          matched := 'person_name:' || candidate;
          EXIT;
        END IF;
      END LOOP;
    END IF;

    IF matched IS NULL THEN CONTINUE; END IF;

    SELECT EXISTS (
      SELECT 1 FROM public.paige_admin_notifications
      WHERE source_workflow_key = 'doctrine_116_sweep'
        AND body LIKE '%slug=' || rec.s_slug || '%'
        AND created_at > now() - interval '7 days'
    ) INTO already_notified;

    UPDATE public.paige_subagents AS t
       SET enabled = false,
           auto_disabled_reason = 'doctrine_116: ' || matched || ' (swept ' || now()::text || ')'
     WHERE t.slug = rec.s_slug;

    IF NOT already_notified THEN
      INSERT INTO public.paige_admin_notifications (severity, title, body, source_workflow_key, assigned_role, scope)
      VALUES (
        CASE WHEN rec.s_enabled THEN 'urgent' ELSE 'info' END,
        'Doctrine §116 sweep: ' || rec.s_name || ' disabled',
        'Sub-agent slug=' || rec.s_slug || ' system_prompt contained a named individual or business — ' || matched ||
        '. Use archetype phrasing only ("a client", "the contact", "their business").',
        'doctrine_116_sweep',
        'admin',
        'admin'
      );
    END IF;

    out_slug := rec.s_slug;
    out_action := CASE WHEN rec.s_enabled THEN 're_disabled' ELSE 'audit_stamped' END;
    out_match := matched;
    RETURN NEXT;
  END LOOP;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.enforce_subagent_doctrine_124()
 RETURNS TABLE(out_slug text, out_action text, out_pattern text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  rec record;
  patterns text[][] := ARRAY[
    ['claims_tool_invocation', '\m(you\s+(can\s+)?(call|invoke|use|run|execute|trigger|fire))\s+(list_subagents|list_skills|list_workflows|tool_invoke|tool_search|paige[_-]mcp|the\s+(mcp|registry|tools?|orchestrator))'],
    ['names_registry_tools',   '\m(list_subagents|list_skills|list_workflows|tool_invoke|tool_search)\M'],
    ['claims_edge_call',       '\m(call|invoke|hit|fetch)\s+(an?\s+)?(edge\s+function|supabase\s+function|rpc)\M'],
    ['claims_mcp_access',      '\m(use|access|via|through)\s+(the\s+)?mcp\M']
  ];
  i int;
  matched text;
  already_notified boolean;
BEGIN
  FOR rec IN
    SELECT s.slug AS s_slug, s.name AS s_name, s.enabled AS s_enabled, s.system_prompt AS s_prompt
    FROM public.paige_subagents s
    WHERE s.runtime = 'soft' AND s.system_prompt IS NOT NULL
  LOOP
    matched := NULL;
    FOR i IN 1 .. array_length(patterns, 1) LOOP
      IF rec.s_prompt ~* patterns[i][2] THEN
        matched := patterns[i][1];
        EXIT;
      END IF;
    END LOOP;

    IF matched IS NULL THEN CONTINUE; END IF;

    SELECT EXISTS (
      SELECT 1 FROM public.paige_admin_notifications
      WHERE source_workflow_key = 'doctrine_124_sweep'
        AND body LIKE '%slug=' || rec.s_slug || '%'
        AND created_at > now() - interval '7 days'
    ) INTO already_notified;

    UPDATE public.paige_subagents AS t
       SET enabled = false,
           auto_disabled_reason = 'doctrine_124_v2: ' || matched || ' (swept ' || now()::text || ')'
     WHERE t.slug = rec.s_slug;

    IF NOT already_notified THEN
      INSERT INTO public.paige_admin_notifications (severity, title, body, source_workflow_key, assigned_role, scope)
      VALUES (
        CASE WHEN rec.s_enabled THEN 'urgent' ELSE 'info' END,
        'Doctrine §124 sweep: ' || rec.s_name || ' disabled',
        'Soft sub-agent slug=' || rec.s_slug || ' matched pattern=' || matched ||
        '. ' || CASE WHEN rec.s_enabled
                  THEN 'Was ENABLED — re-enable detected and reverted.'
                  ELSE 'Already disabled; reason stamped for audit trail.' END,
        'doctrine_124_sweep',
        'admin',
        'admin'
      );
    END IF;

    out_slug := rec.s_slug;
    out_action := CASE WHEN rec.s_enabled THEN 're_disabled' ELSE 'audit_stamped' END;
    out_pattern := matched;
    RETURN NEXT;
  END LOOP;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.enqueue_email(queue_name text, payload jsonb)
 RETURNS bigint
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pgmq'
AS $function$
BEGIN
  RETURN pgmq.send(queue_name, payload);
EXCEPTION WHEN undefined_table THEN
  PERFORM pgmq.create(queue_name);
  RETURN pgmq.send(queue_name, payload);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.ensure_client_role_self_heal()
 RETURNS TABLE(healed boolean, onboarding_stage text, client_id uuid)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user uuid := auth.uid();
  v_client_id uuid;
  v_stage text;
  v_had_role boolean;
  v_healed boolean := false;
BEGIN
  IF v_user IS NULL THEN
    RETURN;
  END IF;

  SELECT id, clients.onboarding_stage INTO v_client_id, v_stage
  FROM public.clients
  WHERE linked_user_id = v_user
  LIMIT 1;

  IF v_client_id IS NULL THEN
    RETURN;
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM public.user_roles WHERE user_id = v_user AND role = 'client'
  ) INTO v_had_role;

  IF NOT v_had_role THEN
    INSERT INTO public.user_roles (user_id, role)
    VALUES (v_user, 'client')
    ON CONFLICT (user_id, role) DO NOTHING;
    v_healed := true;
  END IF;

  IF v_stage IS NULL THEN
    UPDATE public.clients
       SET onboarding_stage = 'invited'
     WHERE id = v_client_id;
    v_stage := 'invited';
    v_healed := true;
  END IF;

  IF v_healed THEN
    BEGIN
      INSERT INTO public.paige_audit_log (actor_user_id, action, target_type, target_id, payload)
      VALUES (v_user, 'client_role_self_heal', 'client', v_client_id,
              jsonb_build_object('granted_role', NOT v_had_role, 'seeded_stage', v_stage));
    EXCEPTION WHEN OTHERS THEN
      NULL;
    END;
  END IF;

  RETURN QUERY SELECT v_healed, v_stage, v_client_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.ensure_owner_admin()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  owner_email text;
  uid uuid;
begin
  select o.owner_email into owner_email from public.app_settings_owner o limit 1;
  if owner_email is null then
    return;
  end if;

  select id into uid from auth.users where email = owner_email limit 1;
  if uid is null then
    return;
  end if;

  -- assumes public.app_role enum with value 'admin' exists
  insert into public.user_roles (user_id, role)
  values (uid, 'admin'::public.app_role)
  on conflict (user_id, role) do nothing;
end;
$function$
;

