  INSERT INTO public.tenant_features(tenant_id) VALUES (NEW.id)
  ON CONFLICT (tenant_id) DO NOTHING;
  RETURN NEW;
END; $function$
;

CREATE OR REPLACE FUNCTION public.expire_prior_pending_readiness_proposals()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.status = 'pending' THEN
    UPDATE public.paige_readiness_proposals
       SET status = 'expired', updated_at = now()
     WHERE contact_id = NEW.contact_id
       AND id <> NEW.id
       AND status = 'pending';
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.expire_stale_readiness_proposals()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE expired_count int;
BEGIN
  UPDATE public.paige_readiness_proposals
     SET status = 'expired', updated_at = now()
   WHERE status = 'pending' AND expires_at < now();
  GET DIAGNOSTICS expired_count = ROW_COUNT;

  INSERT INTO public.paige_audit_log (action, resource_type, metadata, created_at)
  VALUES (
    'readiness_proposal_ttl_sweep',
    'paige_readiness_proposals',
    jsonb_build_object('expired_count', expired_count, 'ran_at', now()),
    now()
  );
  RETURN expired_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.factory_reset_delete_dispute_related(_user_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  linked_client_ids uuid[];
BEGIN
  SELECT COALESCE(array_agg(id), ARRAY[]::uuid[])
  INTO linked_client_ids
  FROM public.clients
  WHERE linked_user_id = _user_id;

  DELETE FROM public.dispute_outcomes WHERE user_id = _user_id;
  DELETE FROM public.dispute_letters WHERE user_id = _user_id;
  DELETE FROM public.disputes WHERE user_id = _user_id;
  DELETE FROM public.credit_negative_items WHERE user_id = _user_id;
  DELETE FROM public.credit_report_personal_info WHERE user_id = _user_id;

  IF array_length(linked_client_ids, 1) IS NOT NULL THEN
    DELETE FROM public.dispute_outcomes WHERE client_id = ANY(linked_client_ids);
    DELETE FROM public.disputes WHERE client_id = ANY(linked_client_ids);
    DELETE FROM public.credit_negative_items WHERE client_id = ANY(linked_client_ids);
    DELETE FROM public.credit_report_personal_info WHERE client_id = ANY(linked_client_ids);
  END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.fire_team_event(payload jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  edge_url text;
  service_key text;
BEGIN
  SELECT decrypted_secret INTO edge_url FROM vault.decrypted_secrets WHERE name = 'project_url' LIMIT 1;
  SELECT decrypted_secret INTO service_key FROM vault.decrypted_secrets WHERE name = 'service_role_key' LIMIT 1;
  IF edge_url IS NULL OR service_key IS NULL THEN
    RETURN;
  END IF;
  PERFORM net.http_post(
    url := edge_url || '/functions/v1/notify-team-event',
    headers := jsonb_build_object('Content-Type','application/json','Authorization','Bearer '||service_key),
    body := payload
  );
EXCEPTION WHEN OTHERS THEN
  RAISE NOTICE 'fire_team_event failed: %', SQLERRM;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.generate_paige_invoice_number()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  prefix text := 'INV-' || to_char(now(), 'YYYYMM') || '-';
  next_seq int;
BEGIN
  IF NEW.invoice_number IS NULL OR NEW.invoice_number = '' THEN
    SELECT COALESCE(MAX( (regexp_replace(invoice_number, '^.*-', ''))::int ), 0) + 1
      INTO next_seq
      FROM public.paige_invoices
     WHERE invoice_number LIKE prefix || '%';
    NEW.invoice_number := prefix || lpad(next_seq::text, 4, '0');
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_approval_queue_counts()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _pending int;
  _by_type jsonb;
BEGIN
  SELECT count(*) INTO _pending
  FROM public.paige_pending_approvals
  WHERE status = 'pending';

  SELECT COALESCE(jsonb_object_agg(type, ct), '{}'::jsonb) INTO _by_type
  FROM (
    SELECT type, count(*) AS ct
    FROM public.paige_pending_approvals
    WHERE status = 'pending'
    GROUP BY type
  ) s;

  RETURN jsonb_build_object('pending', _pending, 'by_type', _by_type);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_broker_team_member(_auth_user_id uuid)
 RETURNS TABLE(id uuid, broker_id uuid, email text, first_name text, last_name text, role text, status text, permissions jsonb, business_name text, firm_description text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT 
    tm.id, tm.broker_id, tm.email, tm.first_name, tm.last_name, tm.role, tm.status, tm.permissions,
    bp.business_name, bp.firm_description
  FROM public.broker_team_members tm
  JOIN public.broker_profiles bp ON bp.id = tm.broker_id
