CREATE OR REPLACE FUNCTION public.get_public_booking_page(_slug text)
 RETURNS TABLE(user_id uuid, tenant_id uuid, timezone text, default_meeting_duration_min integer, buffer_before_min integer, buffer_after_min integer, availability_json jsonb, display_name text)
