CREATE OR REPLACE FUNCTION public.get_user_business_limit(_user_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _max integer;
  _add integer;
  _plan text;
BEGIN
  SELECT max_businesses, additional_businesses_count
    INTO _max, _add
  FROM public.user_business_limits
  WHERE user_id = _user_id;

  IF _max IS NULL THEN
    SELECT plan_slug INTO _plan
    FROM public.user_subscriptions
    WHERE user_id = _user_id
    LIMIT 1;

    _max := public.default_max_businesses_for_plan(_plan);
    _add := 0;
  END IF;

  RETURN COALESCE(_max, 1) + COALESCE(_add, 0);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_user_primary_tenant(_user_id uuid)
 RETURNS TABLE(tenant_id uuid, tenant_name text, member_role text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  WITH ranked AS (
    SELECT
      t.id AS tenant_id,
      t.name AS tenant_name,
      tm.role::text AS member_role,
      CASE tm.role::text
        WHEN 'owner' THEN 1
        WHEN 'admin' THEN 2
        WHEN 'coach' THEN 3
        ELSE 9
      END AS rank
    FROM public.tenant_members tm
    JOIN public.tenants t ON t.id = tm.tenant_id
    WHERE tm.user_id = _user_id AND tm.status = 'active'
    UNION ALL
    SELECT t.id, t.name, 'owner', 1
    FROM public.tenants t
    WHERE t.owner_user_id = _user_id
  )
  SELECT tenant_id, tenant_name, member_role
  FROM ranked
  ORDER BY rank ASC
  LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.get_workspace_brand()
 RETURNS TABLE(tenant_id uuid, tenant_name text, white_label_ai_connect boolean, brand_display_name text, brand_logo_url text, legal_business_name text)
 LANGUAGE sql
