  WHERE c.linked_user_id = auth.uid()
  LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.grant_tenant_member_role(_user_id uuid, _role app_role, _tenant_id uuid DEFAULT NULL::uuid, _reason text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _caller uuid := auth.uid();
  _resolved_tenant uuid;
  _tenant_role public.tenant_role;
BEGIN
  IF _caller IS NULL THEN RAISE EXCEPTION 'Authentication required'; END IF;
  _resolved_tenant := COALESCE(_tenant_id, public.current_user_tenant_id());
  IF _resolved_tenant IS NULL THEN RAISE EXCEPTION 'No active tenant context'; END IF;
  IF NOT (public.is_platform_owner() OR public.is_tenant_admin(_resolved_tenant)) THEN
    RAISE EXCEPTION 'Tenant admin privileges required';
  END IF;
  IF _role = 'super_admin'::public.app_role THEN
    RAISE EXCEPTION 'Cannot grant platform owner role here';
  END IF;

  _tenant_role := public.map_app_role_to_tenant_role(_role);

  INSERT INTO public.user_roles (user_id, role) VALUES (_user_id, _role)
  ON CONFLICT (user_id, role) DO NOTHING;

  INSERT INTO public.tenant_members (tenant_id, user_id, role, status, invited_at, joined_at)
  VALUES (_resolved_tenant, _user_id, _tenant_role, 'active', now(), now())
  ON CONFLICT (tenant_id, user_id) DO UPDATE
    SET role = CASE
          WHEN public.tenant_members.role = 'owner'::public.tenant_role THEN public.tenant_members.role
          WHEN EXCLUDED.role = 'admin'::public.tenant_role THEN 'admin'::public.tenant_role
          WHEN EXCLUDED.role = 'coach'::public.tenant_role
               AND public.tenant_members.role NOT IN ('admin'::public.tenant_role, 'owner'::public.tenant_role)
            THEN 'coach'::public.tenant_role
          ELSE public.tenant_members.role
        END,
        status = 'active',
        joined_at = COALESCE(public.tenant_members.joined_at, now()),
        updated_at = now();

  UPDATE public.profiles SET active_tenant_id = _resolved_tenant
   WHERE user_id = _user_id AND (active_tenant_id IS NULL OR public.is_platform_owner());

  INSERT INTO public.audit_logs (user_id, entity, action, entity_id, data)
  VALUES (_caller, 'tenant_member', 'grant_tenant_member_role', _user_id,
          jsonb_build_object('tenant_id', _resolved_tenant, 'role', _role, 'reason', _reason));

  INSERT INTO public.paige_audit_log
    (actor_user_id, actor_role, action, target_type, target_id, payload, tenant_id)
  VALUES (_caller, 'admin', 'role:grant', 'user_role', _user_id,
          jsonb_build_object('to_role', _role, 'tenant_id', _resolved_tenant, 'reason', _reason),
          _resolved_tenant);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.grant_tenant_member_role(_user_id uuid, _role app_role, _tenant_id uuid DEFAULT NULL::uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _caller uuid := auth.uid();
  _resolved_tenant uuid;
  _tenant_role public.tenant_role;
BEGIN
  IF _caller IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  _resolved_tenant := COALESCE(_tenant_id, public.current_user_tenant_id());

  IF _resolved_tenant IS NULL THEN
    RAISE EXCEPTION 'No active tenant context';
  END IF;

  IF NOT (public.is_platform_owner() OR public.is_tenant_admin(_resolved_tenant)) THEN
    RAISE EXCEPTION 'Tenant admin privileges required';
  END IF;

  IF _role = 'super_admin'::public.app_role THEN
    RAISE EXCEPTION 'Cannot grant platform owner role here';
  END IF;

  _tenant_role := public.map_app_role_to_tenant_role(_role);

  INSERT INTO public.user_roles (user_id, role)
  VALUES (_user_id, _role)
  ON CONFLICT (user_id, role) DO NOTHING;

  INSERT INTO public.tenant_members (tenant_id, user_id, role, status, invited_at, joined_at)
  VALUES (_resolved_tenant, _user_id, _tenant_role, 'active', now(), now())
  ON CONFLICT (tenant_id, user_id) DO UPDATE
    SET role = CASE
          WHEN public.tenant_members.role = 'owner'::public.tenant_role THEN public.tenant_members.role
          WHEN EXCLUDED.role = 'admin'::public.tenant_role THEN 'admin'::public.tenant_role
          WHEN EXCLUDED.role = 'coach'::public.tenant_role
               AND public.tenant_members.role NOT IN ('admin'::public.tenant_role, 'owner'::public.tenant_role)
            THEN 'coach'::public.tenant_role
          ELSE public.tenant_members.role
        END,
        status = 'active',
        joined_at = COALESCE(public.tenant_members.joined_at, now()),
        updated_at = now();

  UPDATE public.profiles
     SET active_tenant_id = _resolved_tenant
   WHERE user_id = _user_id
     AND (active_tenant_id IS NULL OR public.is_platform_owner());

  INSERT INTO public.audit_logs (user_id, entity, action, entity_id, data)
  VALUES (_caller, 'tenant_member', 'grant_tenant_member_role', _user_id,
          jsonb_build_object('tenant_id', _resolved_tenant, 'role', _role));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_data_subject_request(_tenant_id uuid, _contact_id uuid, _request_type text, _corrections jsonb DEFAULT NULL::jsonb, _reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _actor uuid := auth.uid();
  _is_platform_owner boolean := public.is_platform_owner();
  _is_tenant_admin boolean := CASE WHEN _actor IS NULL THEN false
                                   ELSE public.is_tenant_admin(_tenant_id) END;
  _contact record;
  _export jsonb;
  _allowed_correction_fields text[] := ARRAY[
    'first_name','last_name','email','phone','entity_name',
    'city','state','zip','address_line1','address_line2'
  ];
  _patch jsonb := '{}'::jsonb;
  _k text;
BEGIN
  IF NOT (_is_platform_owner OR _is_tenant_admin) THEN
    RAISE EXCEPTION 'forbidden: only tenant admins may handle data subject requests';
  END IF;

  IF _request_type NOT IN ('export','delete','correct','portability') THEN
    RAISE EXCEPTION 'invalid_request_type: %', _request_type;
  END IF;

  SELECT * INTO _contact FROM public.clients
   WHERE id = _contact_id AND tenant_id = _tenant_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'contact_not_found_in_tenant';
  END IF;

  -- Log to pii_access_log (7-year retention marker in payload)
  INSERT INTO public.pii_access_log (user_id, accessed_by, table_name, column_name, action, reason)
  VALUES (
    COALESCE(_contact.linked_user_id, _actor),
    _actor,
    'clients',
    'dsr',
    _request_type,
    COALESCE(_reason, 'data_subject_request')
  );

  INSERT INTO public.paige_audit_log (actor_user_id, actor_role, action, target_type, target_id, payload)
  VALUES (
    _actor,
    CASE WHEN _is_platform_owner THEN 'platform_owner' ELSE 'tenant_admin' END,
    'dsr.' || _request_type,
    'clients',
    _contact_id,
    jsonb_build_object(
      'tenant_id', _tenant_id,
      'reason', _reason,
      'retention_years', 7,
      'retention_expires_at', (now() + interval '7 years')
    )
  );

  IF _request_type IN ('export','portability') THEN
    SELECT jsonb_build_object(
      'contact', to_jsonb(_contact) - 'ssn_encrypted',
      'notes', COALESCE((SELECT jsonb_agg(to_jsonb(n)) FROM public.client_notes n WHERE n.client_id = _contact_id), '[]'::jsonb),
      'deals', COALESCE((SELECT jsonb_agg(to_jsonb(d)) FROM public.deals d WHERE d.contact_id = _contact_id), '[]'::jsonb),
      'files', COALESCE((SELECT jsonb_agg(to_jsonb(f)) FROM public.client_files f WHERE f.client_id = _contact_id), '[]'::jsonb),
      'memory', COALESCE((SELECT jsonb_agg(to_jsonb(m)) FROM public.client_memory m WHERE m.client_id = _contact_id), '[]'::jsonb)
    ) INTO _export;
    RETURN jsonb_build_object(
      'ok', true,
      'request_type', _request_type,
      'format', CASE WHEN _request_type = 'portability' THEN 'json_portable' ELSE 'json' END,
      'data', _export
    );
  END IF;

  IF _request_type = 'correct' THEN
    IF _corrections IS NULL OR jsonb_typeof(_corrections) <> 'object' THEN
      RAISE EXCEPTION 'corrections_required_for_correct';
    END IF;
    FOR _k IN SELECT jsonb_object_keys(_corrections) LOOP
      IF _k = ANY(_allowed_correction_fields) THEN
        _patch := _patch || jsonb_build_object(_k, _corrections->_k);
      END IF;
    END LOOP;
    IF _patch = '{}'::jsonb THEN
      RAISE EXCEPTION 'no_allowed_correction_fields_present';
    END IF;
    UPDATE public.clients c
       SET first_name    = COALESCE(_patch->>'first_name', c.first_name),
           last_name     = COALESCE(_patch->>'last_name', c.last_name),
           email         = COALESCE(_patch->>'email', c.email),
           phone         = COALESCE(_patch->>'phone', c.phone),
           entity_name   = COALESCE(_patch->>'entity_name', c.entity_name),
           city          = COALESCE(_patch->>'city', c.city),
           state         = COALESCE(_patch->>'state', c.state),
           zip           = COALESCE(_patch->>'zip', c.zip),
           address_line1 = COALESCE(_patch->>'address_line1', c.address_line1),
           address_line2 = COALESCE(_patch->>'address_line2', c.address_line2),
           updated_at    = now()
     WHERE c.id = _contact_id AND c.tenant_id = _tenant_id;
    RETURN jsonb_build_object('ok', true, 'request_type','correct','applied', _patch);
  END IF;

  IF _request_type = 'delete' THEN
    -- Soft delete: null PII and mark deletion; keeps audit trail intact.
    UPDATE public.clients
       SET first_name = 'REDACTED', last_name = 'REDACTED',
           email = NULL, phone = NULL, ssn_last_4 = NULL,
           address_line1 = NULL, address_line2 = NULL,
           city = NULL, state = NULL, zip = NULL,
           lifecycle_stage = 'archived',
           updated_at = now()
     WHERE id = _contact_id AND tenant_id = _tenant_id;
    INSERT INTO public.data_deletion_requests (user_id, requested_at, status, reason)
    VALUES (COALESCE(_contact.linked_user_id, _contact_id), now(), 'processed', COALESCE(_reason,'dsr_delete'));
    RETURN jsonb_build_object('ok', true, 'request_type','delete','redacted', true);
  END IF;

  RETURN jsonb_build_object('ok', false, 'error','unhandled');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_new_user_referral()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  if new.raw_user_meta_data is not null
     and new.raw_user_meta_data ? 'referral_code'
  then
    update public.profiles
       set referral_code = new.raw_user_meta_data->>'referral_code'
     where user_id = new.id
       and referral_code is null;
  end if;
  return new;
end $function$
;

CREATE OR REPLACE FUNCTION public.handle_new_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''
AS $function$
declare
  v_ref_code  text;
  v_full_name text;
  v_first     text;
  v_last      text;
  v_owner_id  uuid;
begin
  v_ref_code := nullif(upper(trim(new.raw_user_meta_data->>'referral_code')), '');
  v_full_name := coalesce(new.raw_user_meta_data->>'full_name', '');

  insert into public.profiles (user_id, full_name, referral_code)
  values (new.id, nullif(v_full_name, ''), v_ref_code);

  insert into public.user_roles (user_id, role)
  values (new.id, 'user');

  -- Auto-create CRM contact for every new signup (skip admins; there are none at insert time anyway).
  v_first := coalesce(nullif(split_part(v_full_name, ' ', 1), ''), split_part(coalesce(new.email, ''), '@', 1));
  v_last  := coalesce(nullif(substring(v_full_name from position(' ' in v_full_name) + 1), ''), '');

  -- Owner of the platform owns auto-created contacts so admins can see them
  select u.id into v_owner_id
  from auth.users u
  join public.app_settings_owner o on lower(u.email) = lower(o.owner_email)
  limit 1;

  if v_owner_id is null then
    v_owner_id := new.id; -- fallback so NOT NULL constraint holds
  end if;

  begin
    insert into public.clients (
      created_by, first_name, last_name, email, linked_user_id,
      lifecycle_stage, source, status
    ) values (
      v_owner_id,
      coalesce(nullif(v_first, ''), 'New'),
      v_last,
      new.email,
      new.id,
      'lead',
      'signup',
      'active'
    );
  exception when others then
    raise warning 'handle_new_user: client autocreate failed: %', sqlerrm;
  end;

  return new;
end;
$function$
;

