CREATE OR REPLACE FUNCTION public.has_tenant_role(_user_id uuid, _tenant_id uuid, _role text)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT EXISTS (
    SELECT 1
    FROM public.tenant_members tm
    WHERE tm.user_id = _user_id
      AND tm.tenant_id = _tenant_id
      AND tm.role::text = _role
      AND tm.status = 'active'
  ) OR (
    _role = 'owner' AND EXISTS (
      SELECT 1 FROM public.tenants t WHERE t.id = _tenant_id AND t.owner_user_id = _user_id
    )
  );
$function$
;

CREATE OR REPLACE FUNCTION public.hash_invitation_token()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
BEGIN
  NEW.token_hash := encode(extensions.digest(NEW.token, 'sha256'), 'hex');
  NEW.token := NULL;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.increment_readiness_scan_counters(_run_id uuid, _contacts_scanned integer DEFAULT 0, _proposals_generated integer DEFAULT 0, _proposals_insufficient_data integer DEFAULT 0, _credit_provider_calls integer DEFAULT 0, _credit_provider_cost_usd numeric DEFAULT 0)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  UPDATE public.paige_readiness_scan_runs
     SET contacts_scanned = contacts_scanned + COALESCE(_contacts_scanned, 0),
         proposals_generated = proposals_generated + COALESCE(_proposals_generated, 0),
         proposals_insufficient_data = proposals_insufficient_data + COALESCE(_proposals_insufficient_data, 0),
         credit_provider_calls_count = credit_provider_calls_count + COALESCE(_credit_provider_calls, 0),
         credit_provider_cost_usd = credit_provider_cost_usd + COALESCE(_credit_provider_cost_usd, 0)
   WHERE id = _run_id;
END;
$function$
;

