    WHERE tm.user_id = _user_id
      AND tm.role = 'owner'
      AND tm.status = 'active'
      AND (_tenant_id IS NULL OR tm.tenant_id = _tenant_id)
  );
$function$
;

CREATE OR REPLACE FUNCTION public.list_pending_customer_actions(p_contact_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public'
AS $function$
DECLARE v_rows jsonb;
BEGIN
  SELECT COALESCE(jsonb_agg(row_to_json(t) ORDER BY t.created_at DESC), '[]'::jsonb)
    INTO v_rows
  FROM (
    SELECT a.id, a.action_type, a.title, a.body, a.status, a.expires_at, a.created_at,
      (SELECT COALESCE(jsonb_agg(row_to_json(r) ORDER BY r.created_at), '[]'::jsonb)
         FROM public.paige_customer_responses r WHERE r.action_id = a.id) AS responses
    FROM public.paige_customer_actions a
    WHERE a.contact_id = p_contact_id
  ) t;
  RETURN jsonb_build_object('ok', true, 'actions', v_rows);
END; $function$
;

CREATE OR REPLACE FUNCTION public.load_contact_context(p_contact_id uuid, p_scopes text[] DEFAULT ARRAY['contact'::text])
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  v_client public.clients%ROWTYPE;
  v_bundle jsonb := '{}'::jsonb;
  v_surfaces text[] := '{}';
  v_row_count int := 0;
  v_load_id uuid;
  v_consent boolean;
  v_tenant uuid;
  r record;
  q text;
  data jsonb;
BEGIN
  SELECT * INTO v_client FROM public.clients WHERE id = p_contact_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'error', 'CONTACT_NOT_FOUND');
  END IF;
  v_tenant := v_client.tenant_id;
  v_consent := COALESCE(v_client.paige_shared_context_consent, false);
  IF v_client.linked_user_id = auth.uid() THEN
    v_consent := true;
  END IF;
  IF NOT v_consent THEN
    INSERT INTO public.paige_context_loads(tenant_id, contact_id, caller_user_id, caller_role, scope, surfaces_used, row_count, consent_state)
    VALUES (v_tenant, p_contact_id, auth.uid(), 'coach', 'contact', '{}', 0, 'denied')
    RETURNING id INTO v_load_id;
    RETURN jsonb_build_object(
      'ok', false,
      'error', 'CONSENT_NOT_GRANTED',
      'message', 'Customer has not consented to sharing context with coach''s Paige. Ask them to enable in their workspace settings.',
      'load_id', v_load_id
    );
  END IF;
  FOR r IN
    SELECT surface, table_name, context_fk_column, context_field_whitelist, context_max_rows, context_priority
    FROM public.paige_data_source_registry
    WHERE paige_context_eligible = true
      AND context_scope = ANY(p_scopes)
      AND array_length(context_field_whitelist,1) > 0
      AND table_name IS NOT NULL
      AND context_fk_column IS NOT NULL
    ORDER BY context_priority ASC
  LOOP
    BEGIN
      q := format(
        'SELECT coalesce(jsonb_agg(row_to_json(t)), ''[]''::jsonb) FROM (SELECT %s FROM public.%I WHERE %I = $1 LIMIT %s) t',
        (SELECT string_agg(quote_ident(c), ',') FROM unnest(r.context_field_whitelist) c),
        r.table_name,
        r.context_fk_column,
        r.context_max_rows
      );
      EXECUTE q INTO data USING p_contact_id;
      IF data IS NOT NULL AND jsonb_array_length(data) > 0 THEN
        v_bundle := v_bundle || jsonb_build_object(r.surface, data);
        v_surfaces := array_append(v_surfaces, r.surface);
        v_row_count := v_row_count + jsonb_array_length(data);
      END IF;
    EXCEPTION WHEN OTHERS THEN
      CONTINUE;
    END;
  END LOOP;
  INSERT INTO public.paige_context_loads(tenant_id, contact_id, caller_user_id, caller_role, scope, surfaces_used, row_count, consent_state)
  VALUES (v_tenant, p_contact_id, auth.uid(), 'coach', 'contact', v_surfaces, v_row_count,
          CASE WHEN v_client.linked_user_id = auth.uid() THEN 'self' ELSE 'granted' END)
  RETURNING id INTO v_load_id;
  RETURN jsonb_build_object(
    'ok', true,
    'load_id', v_load_id,
    'contact_id', p_contact_id,
    'surfaces_used', v_surfaces,
    'row_count', v_row_count,
    'bundle', v_bundle
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.load_self_context()
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  v_contact_id uuid;
BEGIN
  SELECT id INTO v_contact_id FROM public.clients WHERE linked_user_id = auth.uid() LIMIT 1;
  IF v_contact_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'NO_LINKED_CONTACT');
  END IF;
  RETURN public.load_contact_context(v_contact_id, ARRAY['contact','self']::text[]);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.log_credit_verification_pii_access()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF TG_OP = 'UPDATE' THEN
    -- Check if any sensitive fields were modified
    IF (OLD.ssn_last_4 IS DISTINCT FROM NEW.ssn_last_4) OR
       (OLD.date_of_birth IS DISTINCT FROM NEW.date_of_birth) OR
       (OLD.experian_api_user_id IS DISTINCT FROM NEW.experian_api_user_id) OR
       (OLD.equifax_api_user_id IS DISTINCT FROM NEW.equifax_api_user_id) OR
       (OLD.transunion_api_user_id IS DISTINCT FROM NEW.transunion_api_user_id) THEN
      
      INSERT INTO public.pii_access_log (
        accessed_user_id,
        accessor_user_id,
        table_name,
        field_names,
        access_type
      ) VALUES (
        NEW.user_id,
        auth.uid(),
        'credit_report_verifications',
        ARRAY['ssn_last_4', 'date_of_birth', 'bureau_api_user_ids'],
        'update'
      );
    END IF;
  END IF;
  
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.log_profile_pii_access()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF TG_OP = 'UPDATE' THEN
    IF (OLD.ssn_encrypted IS DISTINCT FROM NEW.ssn_encrypted) OR
       (OLD.date_of_birth IS DISTINCT FROM NEW.date_of_birth) THEN
      
      INSERT INTO public.pii_access_log (
        accessed_user_id,
        accessor_user_id,
        table_name,
        field_names,
        access_type
      ) VALUES (
        NEW.user_id,
        auth.uid(),
        'profiles',
        ARRAY['ssn_encrypted', 'date_of_birth'],
        'update'
      );
    END IF;
  END IF;
  
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.lookup_client_by_account_number(_account_number text)
 RETURNS TABLE(id uuid, tenant_id uuid, account_number text, linked_user_id uuid, first_name text, last_name text, email text, phone text, entity_name text, lifecycle_stage text, status text, created_at timestamp with time zone)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT c.id, c.tenant_id, c.account_number, c.linked_user_id,
         c.first_name, c.last_name, c.email, c.phone,
         c.entity_name, c.lifecycle_stage::text, c.status::text, c.created_at
  FROM public.clients c
  WHERE c.account_number = _account_number
    AND (public.is_platform_owner() OR c.tenant_id = public.current_user_tenant_id())
  LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.map_app_role_to_tenant_role(_app_role app_role)
 RETURNS tenant_role
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public'
AS $function$
  SELECT CASE _app_role
    WHEN 'admin'::public.app_role THEN 'admin'::public.tenant_role
    WHEN 'coach'::public.app_role THEN 'coach'::public.tenant_role
    ELSE 'member'::public.tenant_role
  END
$function$
;

CREATE OR REPLACE FUNCTION public.map_tenant_role_to_app_role(_tenant_role tenant_role)
 RETURNS app_role
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public'
AS $function$
  SELECT CASE _tenant_role
    WHEN 'owner'  THEN 'admin'::app_role
    WHEN 'admin'  THEN 'admin'::app_role
    WHEN 'coach'  THEN 'coach'::app_role
    WHEN 'member' THEN 'user'::app_role
  END
$function$
;

CREATE OR REPLACE FUNCTION public.match_paige_memory(_query_embedding vector, _target_user_id uuid, _target_client_id uuid DEFAULT NULL::uuid, _match_threshold double precision DEFAULT 0.7, _memory_count integer DEFAULT 5, _message_count integer DEFAULT 5)
 RETURNS TABLE(source text, id uuid, memory_type text, content text, similarity double precision, created_at timestamp with time zone)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  -- Authorization: caller must be the owner, the linked client, an admin or a coach
  IF auth.uid() IS DISTINCT FROM _target_user_id
     AND auth.uid() IS DISTINCT FROM _target_client_id
     AND NOT public.has_role(auth.uid(), 'admin'::public.app_role)
     AND NOT public.has_role(auth.uid(), 'coach'::public.app_role) THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;

  RETURN QUERY
  (
    SELECT
      'memory'::text AS source,
      cm.id,
      cm.memory_type,
      cm.content,
      1 - (cm.embedding <=> _query_embedding) AS similarity,
      cm.created_at
    FROM public.client_memory cm
    WHERE cm.is_active = true
      AND cm.embedding IS NOT NULL
      AND (
        cm.client_user_id = _target_user_id
        OR (_target_client_id IS NOT NULL AND cm.client_id = _target_client_id)
      )
      AND 1 - (cm.embedding <=> _query_embedding) >= _match_threshold
    ORDER BY cm.embedding <=> _query_embedding
    LIMIT _memory_count
  )
  UNION ALL
  (
    SELECT
      'chat'::text AS source,
      ce.message_id AS id,
      ce.role AS memory_type,
      ce.content_excerpt AS content,
      1 - (ce.embedding <=> _query_embedding) AS similarity,
      ce.created_at
    FROM public.chat_message_embeddings ce
    WHERE ce.embedding IS NOT NULL
      AND (
        ce.user_id = _target_user_id
        OR (_target_client_id IS NOT NULL AND ce.client_user_id = _target_client_id)
      )
      AND 1 - (ce.embedding <=> _query_embedding) >= _match_threshold
    ORDER BY ce.embedding <=> _query_embedding
    LIMIT _message_count
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.match_rag_documents(_query_embedding vector, _match_threshold numeric DEFAULT 0.75, _match_count integer DEFAULT 3, _document_types text[] DEFAULT NULL::text[], _metadata_filter jsonb DEFAULT NULL::jsonb, _query_text text DEFAULT NULL::text)
 RETURNS TABLE(id uuid, document_type text, title text, summary text, content text, metadata jsonb, similarity double precision, quality_score numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _ids uuid[];
  _is_staff boolean := false;
  _caller uuid := auth.uid();
  _financial_types text[] := ARRAY[
    'business_credit_snapshot','owner_credit_snapshot','banking_snapshot',
    'cash_flow_snapshot','client_financial_brief'
  ];
BEGIN
  IF _caller IS NULL AND auth.role() <> 'service_role' THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;

  IF _caller IS NOT NULL THEN
    _is_staff := public.has_role(_caller, 'admin'::public.app_role)
              OR public.has_role(_caller, 'coach'::public.app_role);
  END IF;

  RETURN QUERY
  WITH ranked AS (
    SELECT
      d.id, d.document_type, d.title, d.summary, d.content, d.metadata,
      1 - (d.embedding <=> _query_embedding) AS similarity,
      d.quality_score
    FROM public.rag_documents d
    WHERE d.is_published = true
      AND d.embedding IS NOT NULL
      AND (_document_types IS NULL OR d.document_type = ANY (_document_types))
      AND (_metadata_filter IS NULL OR d.metadata @> _metadata_filter)
      AND 1 - (d.embedding <=> _query_embedding) >= _match_threshold
      AND (
        NOT (d.document_type = ANY (_financial_types))
        OR auth.role() = 'service_role'
        OR _is_staff
        OR (d.client_id IS NOT NULL AND d.client_id = _caller)
      )
    ORDER BY d.embedding <=> _query_embedding
    LIMIT GREATEST(_match_count, 1)
  )
  SELECT * FROM ranked;

  SELECT COALESCE(array_agg(r.id), ARRAY[]::uuid[]) INTO _ids
  FROM (
    SELECT d.id
    FROM public.rag_documents d
    WHERE d.is_published = true
      AND d.embedding IS NOT NULL
      AND (_document_types IS NULL OR d.document_type = ANY (_document_types))
      AND (_metadata_filter IS NULL OR d.metadata @> _metadata_filter)
      AND 1 - (d.embedding <=> _query_embedding) >= _match_threshold
      AND (
        NOT (d.document_type = ANY (_financial_types))
        OR auth.role() = 'service_role'
        OR _is_staff
        OR (d.client_id IS NOT NULL AND d.client_id = _caller)
      )
    ORDER BY d.embedding <=> _query_embedding
    LIMIT GREATEST(_match_count, 1)
  ) d;

  IF array_length(_ids, 1) IS NOT NULL THEN
    UPDATE public.rag_documents
       SET usage_count = usage_count + 1,
           updated_at = now()
     WHERE id = ANY (_ids);
  END IF;

  BEGIN
    INSERT INTO public.rag_retrieval_log (
      user_id, query_embedding, query_text, retrieved_document_ids
    ) VALUES (
      _caller, _query_embedding, _query_text, COALESCE(_ids, ARRAY[]::uuid[])
    );
  EXCEPTION WHEN OTHERS THEN
    NULL;
  END;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.match_tenant_knowledge(p_tenant_id uuid, p_query_embedding vector, p_match_count integer DEFAULT 6)
 RETURNS TABLE(source_tier text, doc_id uuid, chunk_id uuid, title text, content text, similarity double precision)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
  SELECT
    'tenant'::text                                AS source_tier,
    c.doc_id                                       AS doc_id,
    c.id                                           AS chunk_id,
    d.title                                        AS title,
    c.content                                      AS content,
    1 - (c.embedding <=> p_query_embedding)::float AS similarity
  FROM public.tenant_knowledge_chunks c
  JOIN public.tenant_knowledge_docs d ON d.id = c.doc_id
  WHERE c.tenant_id = p_tenant_id
    AND c.embedding IS NOT NULL
  ORDER BY c.embedding <=> p_query_embedding
  LIMIT p_match_count
$function$
;

CREATE OR REPLACE FUNCTION public.move_to_dlq(source_queue text, dlq_name text, message_id bigint, payload jsonb)
 RETURNS bigint
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pgmq'
AS $function$
DECLARE new_id BIGINT;
BEGIN
  SELECT pgmq.send(dlq_name, payload) INTO new_id;
  PERFORM pgmq.delete(source_queue, message_id);
  RETURN new_id;
EXCEPTION WHEN undefined_table THEN
  BEGIN
    PERFORM pgmq.create(dlq_name);
  EXCEPTION WHEN OTHERS THEN
    NULL;
  END;
  SELECT pgmq.send(dlq_name, payload) INTO new_id;
  BEGIN
    PERFORM pgmq.delete(source_queue, message_id);
  EXCEPTION WHEN undefined_table THEN
    NULL;
  END;
  RETURN new_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.notify_approval_event()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  _event text;
  _project_url text := 'https://bfmyebsjyuoecmjskqhs.supabase.co';
  _service_key text;
BEGIN
  IF TG_OP = 'INSERT' THEN
    IF NEW.status IS NULL OR NEW.status = 'pending' THEN
      _event := 'created';
    ELSE
      RETURN NEW;
    END IF;
  ELSIF TG_OP = 'UPDATE' THEN
    IF NEW.status = 'changes_requested' AND (OLD.status IS DISTINCT FROM 'changes_requested') THEN
      _event := 'changes_requested';
    ELSE
      RETURN NEW;
    END IF;
  ELSE
    RETURN NEW;
  END IF;

  SELECT value INTO _service_key FROM public._internal_secrets WHERE key = 'service_role_key' LIMIT 1;
  IF _service_key IS NULL THEN
    RAISE WARNING 'notify_approval_event: no service_role_key in _internal_secrets';
    RETURN NEW;
  END IF;

  PERFORM extensions.http_post(
    url := _project_url || '/functions/v1/notify-approval-event',
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'Authorization', 'Bearer ' || _service_key
    ),
    body := jsonb_build_object(
      'event', _event,
      'approval_id', NEW.id,
      'rationale', NEW.decision_rationale
    )::text
  );

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'notify_approval_event failed: %', SQLERRM;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.notify_client_on_readiness_approval()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_linked_user uuid;
  v_first_name text;
BEGIN
  IF NEW.status = 'approved' AND (OLD.status IS DISTINCT FROM 'approved') THEN
    SELECT c.linked_user_id, c.first_name
      INTO v_linked_user, v_first_name
      FROM public.clients c
     WHERE c.id = NEW.contact_id;

    IF v_linked_user IS NOT NULL THEN
      INSERT INTO public.notifications (user_id, type, title, message, action_url, metadata)
      VALUES (
        v_linked_user,
        'system',
        'Your coach has a new readiness update',
        COALESCE(v_first_name, 'Your coach') || ' has a new funding readiness update ready for you to review.',
        '/app',
        jsonb_build_object(
          'source', 'readiness_proposal_approved',
          'proposal_id', NEW.id,
          'tenant_id', NEW.tenant_id
        )
      );
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.notify_credit_alert_inserted()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  _project_url text;
  _service_key text;
  _user_id uuid;
  _sms_body text;
  _bureau_label text;
BEGIN
  _project_url := 'https://bfmyebsjyuoecmjskqhs.supabase.co';

  SELECT value INTO _service_key
  FROM public._internal_secrets
  WHERE key = 'service_role_key'
  LIMIT 1;

  IF _service_key IS NULL THEN
    RETURN NEW;
  END IF;

  -- credit_alerts.client_id refers to profiles.user_id
  _user_id := NEW.client_id;

  IF _user_id IS NULL THEN
    RETURN NEW;
  END IF;

  _bureau_label := COALESCE(NEW.bureau, 'your credit');
  _sms_body := 'PaigeAgent Alert: ' || left(COALESCE(NEW.alert_title, 'New credit event'), 80) ||
               '. Check the app for details. Reply STOP to unsubscribe.';

  PERFORM extensions.http_post(
    url := _project_url || '/functions/v1/send-notification',
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'Authorization', 'Bearer ' || _service_key
    ),
    body := jsonb_build_object(
      'user_id', _user_id,
      'message_type', 'credit_alert',
      'email_data', jsonb_build_object(
        'alertType', COALESCE(NEW.alert_type, 'New Credit Event'),
        'alertTitle', COALESCE(NEW.alert_title, 'Credit alert detected'),
        'alertDescription', COALESCE(NEW.alert_description, ''),
        'bureau', _bureau_label
      ),
      'sms_body', _sms_body
    )::text
  );

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'notify_credit_alert_inserted failed: %', SQLERRM;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.notify_dispute_status_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  _title text;
  _body text;
  _project_url text;
  _service_key text;
BEGIN
  -- Only fire when status actually changed
  IF NEW.status IS NOT DISTINCT FROM OLD.status THEN
    RETURN NEW;
  END IF;

  -- Map status -> notification copy
  IF NEW.status::text = 'resolved' THEN
    _title := 'Dispute Resolved';
    _body := 'A dispute on your credit file has been resolved. Log in to see the outcome.';
  ELSIF NEW.status::text IN ('under_review', 'investigating') THEN
    _title := 'Dispute Under Review';
    _body := 'The bureau is reviewing your dispute. We will notify you when a decision is made.';
  ELSE
    -- Other status changes: skip
    RETURN NEW;
  END IF;

  _project_url := 'https://bfmyebsjyuoecmjskqhs.supabase.co';
  -- Read service role key from a per-project secret table populated below
  SELECT value INTO _service_key
  FROM public._internal_secrets
  WHERE key = 'service_role_key'
  LIMIT 1;

  IF _service_key IS NULL THEN
    -- Cannot send without key, but never block the dispute update
    RETURN NEW;
  END IF;

  PERFORM extensions.http_post(
    url := _project_url || '/functions/v1/send-push-notification',
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'Authorization', 'Bearer ' || _service_key
    ),
    body := jsonb_build_object(
      'user_id', NEW.user_id,
      'category', 'dispute_updates',
      'title', _title,
      'body', _body,
      'url', '/app/disputes',
      'tag', 'dispute-' || NEW.id::text,
      'data', jsonb_build_object('dispute_id', NEW.id, 'status', NEW.status)
    )::text
  );

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  -- Never fail the dispute update because of notification errors
  RAISE WARNING 'notify_dispute_status_change failed: %', SQLERRM;
  RETURN NEW;
END;
$function$
;

