CREATE OR REPLACE FUNCTION public.on_deal_stage_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  _rule public.stage_automation_rules%ROWTYPE;
  _tenant_url text;
  _platform_url text;
  _webhook_url text;
  _service_key text;
  _event_id uuid;
  _project_url constant text := 'https://bfmyebsjyuoecmjskqhs.supabase.co';
BEGIN
  IF NEW.stage_id IS NOT DISTINCT FROM OLD.stage_id THEN RETURN NEW; END IF;

  SELECT * INTO _rule FROM public.stage_automation_rules
  WHERE tenant_id = NEW.tenant_id
    AND pipeline_id = NEW.pipeline_id
    AND to_stage_id = NEW.stage_id
    AND (from_stage_id = OLD.stage_id OR from_stage_id IS NULL)
  ORDER BY (from_stage_id IS NOT NULL) DESC
  LIMIT 1;

  IF NOT FOUND THEN
    INSERT INTO public.stage_automation_events
      (tenant_id, deal_id, contact_id, from_stage_id, to_stage_id, status)
      VALUES (NEW.tenant_id, NEW.id, NEW.contact_client_id, OLD.stage_id, NEW.stage_id, 'skipped_no_rule');
    RETURN NEW;
  END IF;

  IF NOT _rule.is_active THEN
    INSERT INTO public.stage_automation_events
      (tenant_id, rule_id, deal_id, contact_id, from_stage_id, to_stage_id, status)
      VALUES (NEW.tenant_id, _rule.id, NEW.id, NEW.contact_client_id, OLD.stage_id, NEW.stage_id, 'skipped_inactive');
    RETURN NEW;
  END IF;

  BEGIN
    SELECT extensions.pgp_sym_decrypt(automation_webhook_url_encrypted, public._automation_webhook_key())
      INTO _tenant_url
    FROM public.tenants WHERE id = NEW.tenant_id;
  EXCEPTION WHEN OTHERS THEN _tenant_url := NULL; END;

  SELECT value INTO _platform_url FROM public._internal_secrets
    WHERE key = 'platform_stage_change_webhook_url' LIMIT 1;

  _webhook_url := COALESCE(_tenant_url, _platform_url);

  IF _webhook_url IS NULL THEN
    INSERT INTO public.stage_automation_events
      (tenant_id, rule_id, deal_id, contact_id, from_stage_id, to_stage_id, status)
      VALUES (NEW.tenant_id, _rule.id, NEW.id, NEW.contact_client_id, OLD.stage_id, NEW.stage_id, 'skipped_no_webhook');
    RETURN NEW;
  END IF;

  INSERT INTO public.stage_automation_events
    (tenant_id, rule_id, deal_id, contact_id, from_stage_id, to_stage_id, status)
    VALUES (NEW.tenant_id, _rule.id, NEW.id, NEW.contact_client_id, OLD.stage_id, NEW.stage_id, 'pending')
    RETURNING id INTO _event_id;

  SELECT value INTO _service_key FROM public._internal_secrets WHERE key = 'service_role_key' LIMIT 1;
  IF _service_key IS NULL THEN
    UPDATE public.stage_automation_events SET status='failed', error='service_role_key missing' WHERE id=_event_id;
    RETURN NEW;
  END IF;

  PERFORM extensions.http_post(
    url := _project_url || '/functions/v1/dispatch-stage-automation',
    headers := jsonb_build_object('Content-Type','application/json','Authorization','Bearer '||_service_key),
    body := jsonb_build_object(
      'event_id', _event_id,
      'webhook_url', _webhook_url,
      'tenant_id', NEW.tenant_id,
      'deal_id', NEW.id,
      'contact_id', NEW.contact_client_id,
      'from_stage_id', OLD.stage_id,
      'to_stage_id', NEW.stage_id,
      'rule', jsonb_build_object(
        'id', _rule.id,
        'compose_intent', _rule.compose_intent,
        'tone', _rule.tone,
        'template_hint', _rule.template_hint,
        'send_mode', _rule.send_mode
      )
    )::text
  );
  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'on_deal_stage_change failed: %', SQLERRM;
  RETURN NEW;
END; $function$
;

CREATE OR REPLACE FUNCTION public.paige_chat_thread_create(p_contact_id uuid, p_lens text, p_title text, p_consent_snapshot jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid       uuid := auth.uid();
  v_tenant_id uuid;
  v_thread_id uuid;
BEGIN
  IF v_uid IS NULL THEN RAISE EXCEPTION 'auth required'; END IF;
  IF p_lens NOT IN ('coach','client','platform') THEN RAISE EXCEPTION 'invalid lens'; END IF;

  IF p_contact_id IS NOT NULL THEN
    SELECT tenant_id INTO v_tenant_id
      FROM public.clients WHERE id = p_contact_id;
    IF v_tenant_id IS NULL THEN
      RAISE EXCEPTION 'contact not found or has no tenant';
    END IF;
  ELSE
    v_tenant_id := public.current_user_tenant_id();
    IF v_tenant_id IS NULL THEN
      RAISE EXCEPTION 'self-mode requires caller tenant';
    END IF;
  END IF;

  INSERT INTO public.paige_chat_threads
    (caller_user_id, contact_id, tenant_id, lens, title,
     consent_snapshot, auto_delete_at, last_message_at)
  VALUES
    (v_uid, p_contact_id, v_tenant_id, p_lens, p_title,
     p_consent_snapshot, now() + interval '90 days', now())
  RETURNING id INTO v_thread_id;

  RETURN v_thread_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.paige_chat_turn_append(p_thread_id uuid, p_role text, p_content text, p_surfaces_used text[], p_load_id uuid, p_model text, p_tokens_used integer, p_latency_ms integer, p_bundle_ref jsonb, p_tool_calls jsonb DEFAULT NULL::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_turn uuid;
  v_owner uuid;
BEGIN
  IF v_uid IS NULL THEN RAISE EXCEPTION 'auth required'; END IF;
  IF p_role NOT IN ('user','assistant','system') THEN RAISE EXCEPTION 'invalid role'; END IF;

  SELECT caller_user_id INTO v_owner FROM public.paige_chat_threads WHERE id = p_thread_id;
  IF v_owner IS NULL THEN RAISE EXCEPTION 'thread not found'; END IF;
  IF v_owner <> v_uid THEN RAISE EXCEPTION 'thread not owned by caller'; END IF;

  INSERT INTO public.paige_chat_turns
    (thread_id, role, content, surfaces_used, load_id, model,
     tokens_used, latency_ms, bundle_ref, tool_calls)
  VALUES
    (p_thread_id, p_role, p_content, p_surfaces_used, p_load_id, p_model,
     p_tokens_used, p_latency_ms, p_bundle_ref, p_tool_calls)
  RETURNING id INTO v_turn;

  UPDATE public.paige_chat_threads
     SET message_count = message_count + 1,
         last_message_at = now(),
         updated_at = now()
   WHERE id = p_thread_id;

  RETURN v_turn;
END;$function$
;

CREATE OR REPLACE FUNCTION public.paige_tool_add_client_note(p_thread_id uuid, p_contact_id uuid, p_content text, p_category text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_owner uuid;
  v_tc uuid;
  v_note uuid;
  v_body text;
  v_tags text[];
BEGIN
  IF v_uid IS NULL THEN RAISE EXCEPTION 'auth required'; END IF;
  IF NOT public.is_staff(v_uid) THEN RAISE EXCEPTION 'staff role required'; END IF;
  IF p_content IS NULL OR length(btrim(p_content))=0 THEN RAISE EXCEPTION 'content required'; END IF;

  SELECT caller_user_id, contact_id INTO v_owner, v_tc
    FROM public.paige_chat_threads WHERE id = p_thread_id;
  IF v_owner IS NULL THEN RAISE EXCEPTION 'thread not found'; END IF;
  IF v_owner <> v_uid THEN RAISE EXCEPTION 'thread not owned by caller'; END IF;
  IF v_tc IS DISTINCT FROM p_contact_id THEN RAISE EXCEPTION 'contact_id mismatch with thread'; END IF;

  v_body := btrim(p_content);
  v_tags := CASE WHEN p_category IS NOT NULL AND length(btrim(p_category)) > 0
                 THEN ARRAY[btrim(lower(p_category))]
                 ELSE ARRAY[]::text[] END;

  INSERT INTO public.client_notes (contact_id, author_user_id, body, tags)
  VALUES (p_contact_id, v_uid, v_body, v_tags)
  RETURNING id INTO v_note;

  INSERT INTO public.paige_audit_log (actor_user_id, action, target_type, target_id, payload)
  VALUES (
    v_uid,
    'tool_call:add_client_note',
    'client_note',
    v_note,
    jsonb_build_object(
      'thread_id', p_thread_id,
      'contact_id', p_contact_id,
      'tool_args', jsonb_build_object(
        'content_preview', left(v_body, 200),
        'category', p_category
      ),
      'tool_result', jsonb_build_object('note_id', v_note, 'ok', true)
    )
  );

  RETURN jsonb_build_object('ok', true, 'note_id', v_note, 'preview', left(v_body, 200));
END;$function$
;

CREATE OR REPLACE FUNCTION public.paige_tool_create_task(p_thread_id uuid, p_contact_id uuid, p_title text, p_description text DEFAULT NULL::text, p_due_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_priority text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_owner uuid;
  v_tc uuid;
  v_task uuid;
  v_title text;
BEGIN
  IF v_uid IS NULL THEN RAISE EXCEPTION 'auth required'; END IF;
  IF NOT public.is_staff(v_uid) THEN RAISE EXCEPTION 'staff role required'; END IF;
  IF p_title IS NULL OR length(btrim(p_title))=0 THEN RAISE EXCEPTION 'title required'; END IF;
  IF p_priority IS NOT NULL AND p_priority NOT IN ('low','medium','high')
    THEN RAISE EXCEPTION 'invalid priority'; END IF;

  SELECT caller_user_id, contact_id INTO v_owner, v_tc
    FROM public.paige_chat_threads WHERE id = p_thread_id;
  IF v_owner IS NULL THEN RAISE EXCEPTION 'thread not found'; END IF;
  IF v_owner <> v_uid THEN RAISE EXCEPTION 'thread not owned by caller'; END IF;
  IF v_tc IS DISTINCT FROM p_contact_id THEN RAISE EXCEPTION 'contact_id mismatch with thread'; END IF;

  v_title := btrim(p_title);

  INSERT INTO public.tasks (user_id, title, description, due_date, status, metadata)
  VALUES (
    v_uid,
    v_title,
    NULLIF(btrim(COALESCE(p_description,'')), ''),
    p_due_date,
    'pending'::task_status,
    jsonb_build_object(
      'contact_id', p_contact_id,
      'source', 'paige_tool_call',
      'thread_id', p_thread_id,
      'priority', COALESCE(p_priority,'medium')
    )
  )
  RETURNING id INTO v_task;

  INSERT INTO public.paige_audit_log (actor_user_id, action, target_type, target_id, payload)
  VALUES (
    v_uid,
    'tool_call:create_task',
    'task',
    v_task,
    jsonb_build_object(
      'thread_id', p_thread_id,
      'contact_id', p_contact_id,
      'tool_args', jsonb_build_object(
        'title', v_title,
        'description', p_description,
        'due_date', p_due_date,
        'priority', p_priority
      ),
      'tool_result', jsonb_build_object('task_id', v_task, 'ok', true)
    )
  );

  RETURN jsonb_build_object('ok', true, 'task_id', v_task, 'title', v_title);
END;$function$
;

CREATE OR REPLACE FUNCTION public.peek_tenant_invite(_token text)
 RETURNS TABLE(tenant_id uuid, tenant_name text, tenant_slug text, brand jsonb, kind text, default_role tenant_role, expires_at timestamp with time zone, is_valid boolean)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _tok public.tenant_invite_tokens;
  _ten public.tenants;
BEGIN
  SELECT * INTO _tok FROM public.tenant_invite_tokens WHERE token = _token;
  IF NOT FOUND THEN
    RETURN;
  END IF;
  SELECT * INTO _ten FROM public.tenants WHERE id = _tok.tenant_id;
  IF NOT FOUND THEN
    RETURN;
  END IF;

  tenant_id    := _ten.id;
  tenant_name  := _ten.name;
  tenant_slug  := _ten.slug;
  brand        := _ten.brand;
  kind         := _tok.kind;
  default_role := _tok.default_role;
  expires_at   := _tok.expires_at;
  is_valid     := (_tok.revoked_at IS NULL)
                  AND (_tok.expires_at > now())
                  AND (_tok.max_uses IS NULL OR _tok.uses < _tok.max_uses);
  RETURN NEXT;
END $function$
;

CREATE OR REPLACE FUNCTION public.platform_decrypt(ciphertext bytea)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE k text;
BEGIN
  IF ciphertext IS NULL THEN RETURN NULL; END IF;
  SELECT value INTO k FROM public._internal_secrets WHERE key='platform_column_key';
  IF k IS NULL THEN RAISE EXCEPTION 'platform_column_key not seeded'; END IF;
  RETURN pgp_sym_decrypt(ciphertext, k);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_encrypt(plaintext text)
 RETURNS bytea
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE k text;
BEGIN
  IF plaintext IS NULL THEN RETURN NULL; END IF;
  SELECT value INTO k FROM public._internal_secrets WHERE key='platform_column_key';
  IF k IS NULL THEN RAISE EXCEPTION 'platform_column_key not seeded'; END IF;
  RETURN pgp_sym_encrypt(plaintext, k);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_metered_events_set_subject_id()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO ''
AS $function$
BEGIN
  IF NEW.subject_id IS NULL THEN
    IF NEW.layer = 'L3_tenant_passthrough' THEN
      NEW.subject_id := NEW.tenant_id;
    END IF;
    -- L4_consumer_direct arm removed with Ship P.0.1.b (deferred to Sprint C.I.F).
  END IF;
  RETURN NEW;
END;
$function$
;

