CREATE OR REPLACE FUNCTION public.prevent_owner_admin_removal()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  owner_email text;
  owner_id uuid;
begin
  select o.owner_email into owner_email from public.app_settings_owner o limit 1;
  if owner_email is null then
    return coalesce(new, old);
  end if;

  select id into owner_id from auth.users where email = owner_email limit 1;

  if tg_op in ('DELETE','UPDATE')
     and old.role = 'admin'::public.app_role
     and old.user_id = owner_id then
    raise exception 'Cannot remove admin role from platform owner';
  end if;

  return coalesce(new, old);
end;
$function$
;

CREATE OR REPLACE FUNCTION public.qb_decrypt_token(_ciphertext text)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  _key TEXT;
BEGIN
  IF auth.role() != 'service_role' THEN
    RAISE EXCEPTION 'Only service role can decrypt QB tokens';
  END IF;
  SELECT value INTO _key FROM public._internal_secrets WHERE key = 'qb_token_key' LIMIT 1;
  IF _key IS NULL THEN
    RAISE EXCEPTION 'qb_token_key not configured';
  END IF;
  RETURN extensions.pgp_sym_decrypt(decode(_ciphertext, 'base64')::bytea, _key);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.qb_encrypt_token(_plaintext text)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  _key TEXT;
BEGIN
  SELECT value INTO _key FROM public._internal_secrets WHERE key = 'qb_token_key' LIMIT 1;
  IF _key IS NULL THEN
    RAISE EXCEPTION 'qb_token_key not configured in _internal_secrets';
  END IF;
  RETURN encode(extensions.pgp_sym_encrypt(_plaintext, _key), 'base64');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rag_recalibrate_quality()
 RETURNS TABLE(flagged_low integer, boosted_high integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _flagged integer := 0;
  _boosted integer := 0;
BEGIN
  IF auth.uid() IS NOT NULL AND NOT public.has_role(auth.uid(), 'admin'::public.app_role) THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;

  -- Boost consistently helpful docs (>=10 retrievals, >=70% helpful).
  WITH boosted AS (
    UPDATE public.rag_documents
       SET quality_score = LEAST(quality_score + 0.05, 1.0),
           updated_at = now()
     WHERE usage_count >= 10
       AND (helpful_count::numeric / NULLIF(usage_count,0)) >= 0.7
     RETURNING 1
  )
  SELECT count(*) INTO _boosted FROM boosted;

  -- Flag low-helpfulness docs (>=10 retrievals, <30% helpful) for admin review.
  WITH flagged AS (
    UPDATE public.rag_documents
       SET metadata = jsonb_set(
                        COALESCE(metadata, '{}'::jsonb),
                        '{flagged_low_helpfulness}',
                        'true'::jsonb,
                        true
                      ),
           updated_at = now()
     WHERE usage_count >= 10
       AND (helpful_count::numeric / NULLIF(usage_count,0)) < 0.3
       AND COALESCE(metadata->>'flagged_low_helpfulness','false') <> 'true'
     RETURNING 1
  )
  SELECT count(*) INTO _flagged FROM flagged;

  RETURN QUERY SELECT _flagged, _boosted;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.reactivate_user(_user_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NOT (public.is_platform_owner() OR public.has_role(auth.uid(), 'admin')) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  UPDATE public.profiles
    SET suspended_at = NULL,
        suspended_reason = NULL,
        suspended_by = NULL,
        updated_at = now()
    WHERE id = _user_id;

  INSERT INTO public.paige_audit_log (actor_user_id, action, target_type, target_id, metadata)
  VALUES (auth.uid(), 'reactivate_user', 'user', _user_id, '{}'::jsonb);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.read_email_batch(queue_name text, batch_size integer, vt integer)
 RETURNS TABLE(msg_id bigint, read_ct integer, message jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pgmq'
AS $function$
BEGIN
  RETURN QUERY SELECT r.msg_id, r.read_ct, r.message FROM pgmq.read(queue_name, vt, batch_size) r;
EXCEPTION WHEN undefined_table THEN
