CREATE OR REPLACE FUNCTION public.reassign_coach_clients(_from_coach uuid, _to_coach uuid)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  affected integer;
BEGIN
  IF NOT (public.is_platform_owner() OR public.has_role(auth.uid(), 'admin')) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  IF _to_coach IS NOT NULL THEN
    IF NOT public.has_role(_to_coach, 'coach') THEN
      RAISE EXCEPTION 'target user is not a coach';
    END IF;
  END IF;

  UPDATE public.clients
    SET assigned_coach_user_id = _to_coach,
        updated_at = now()
    WHERE assigned_coach_user_id = _from_coach;
  GET DIAGNOSTICS affected = ROW_COUNT;

  UPDATE public.coach_clients
    SET status = 'reassigned'
    WHERE coach_user_id = _from_coach AND status = 'active';

  IF _to_coach IS NOT NULL THEN
    INSERT INTO public.coach_clients (coach_user_id, client_id, status)
    SELECT _to_coach, c.id, 'active'
      FROM public.clients c
      WHERE c.assigned_coach_user_id = _to_coach
    ON CONFLICT DO NOTHING;
  END IF;

  INSERT INTO public.paige_audit_log (actor_user_id, action, target_type, target_id, metadata)
  VALUES (
    auth.uid(),
    'reassign_coach_clients',
    'user',
    _from_coach,
    jsonb_build_object('to_coach', _to_coach, 'affected_clients', affected)
  );

  RETURN affected;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_communications_consent(p_email text, p_phone text DEFAULT NULL::text, p_tenant_id uuid DEFAULT NULL::uuid, p_contact_id uuid DEFAULT NULL::uuid, p_email_marketing boolean DEFAULT false, p_sms_marketing boolean DEFAULT false, p_sms_transactional boolean DEFAULT false, p_voice_marketing boolean DEFAULT false, p_source text DEFAULT 'unknown'::text, p_ip_address text DEFAULT NULL::text, p_user_agent text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_id uuid;
  v_doc_version integer;
BEGIN
  IF p_email IS NULL OR length(trim(p_email)) = 0 THEN
    RAISE EXCEPTION 'email is required for communications consent';
  END IF;

  SELECT version INTO v_doc_version
  FROM public.legal_documents
  WHERE slug = 'communications-consent' AND is_current = true
  ORDER BY version DESC LIMIT 1;

  INSERT INTO public.communications_consents (
    user_id, tenant_id, contact_id, email, phone,
    email_transactional, email_marketing,
    sms_transactional, sms_marketing, voice_marketing,
    document_slug, document_version, source, ip_address, user_agent
  )
  VALUES (
    auth.uid(), p_tenant_id, p_contact_id, lower(trim(p_email)), p_phone,
    true, COALESCE(p_email_marketing, false),
    COALESCE(p_sms_transactional, false),
    COALESCE(p_sms_marketing, false),
    COALESCE(p_voice_marketing, false),
    'communications-consent', COALESCE(v_doc_version, 1), p_source, p_ip_address, p_user_agent
  )
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.refresh_analytics_views()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  if auth.uid() is not null
     and not public.has_role(auth.uid(), 'admin'::public.app_role) then
    raise exception 'Unauthorized';
  end if;

  begin
    refresh materialized view concurrently public.analytics_daily_summary;
  exception when others then
    refresh materialized view public.analytics_daily_summary;
  end;

  begin
    refresh materialized view concurrently public.analytics_feature_usage;
  exception when others then
    refresh materialized view public.analytics_feature_usage;
  end;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.reject_affiliate_application(_application_id uuid, _notes text DEFAULT NULL::text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NOT public.has_role(auth.uid(), 'admin'::public.app_role) THEN
    RAISE EXCEPTION 'Unauthorized: admin role required';
  END IF;

  UPDATE public.affiliate_applications
  SET status = 'rejected',
      reviewed_by = auth.uid(),
      reviewed_at = now(),
      review_notes = _notes
  WHERE id = _application_id
    AND status = 'pending';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Application not found or not pending';
  END IF;

  RETURN json_build_object('success', true);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.require_tenant_brand(p_tenant_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_tenant public.tenants%ROWTYPE;
  v_domain public.tenant_email_domains%ROWTYPE;
  v_sender_name text;
  v_brand_name text;
BEGIN
  IF p_tenant_id IS NULL THEN
    RAISE EXCEPTION 'TENANT_SENDER_IDENTITY_NOT_CONFIGURED: tenant_id is null' USING ERRCODE = 'P0001';
  END IF;
  SELECT * INTO v_tenant FROM public.tenants WHERE id = p_tenant_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'TENANT_SENDER_IDENTITY_NOT_CONFIGURED: tenant % not found', p_tenant_id USING ERRCODE = 'P0001';
  END IF;
  v_brand_name  := NULLIF(TRIM(COALESCE(v_tenant.brand->>'name', v_tenant.name)), '');
  v_sender_name := NULLIF(TRIM(COALESCE(v_tenant.brand->>'sender_name', v_brand_name)), '');
  IF v_brand_name IS NULL OR v_sender_name IS NULL THEN
    RAISE EXCEPTION 'TENANT_SENDER_IDENTITY_NOT_CONFIGURED: tenant % missing brand.name/sender_name', p_tenant_id USING ERRCODE = 'P0001';
  END IF;
  SELECT * INTO v_domain
  FROM public.tenant_email_domains
  WHERE tenant_id = p_tenant_id AND status = 'verified'
  ORDER BY is_default DESC, verified_at DESC NULLS LAST
  LIMIT 1;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'TENANT_SENDER_IDENTITY_NOT_CONFIGURED: tenant % has no verified email domain', p_tenant_id USING ERRCODE = 'P0001';
  END IF;
  RETURN jsonb_build_object(
    'tenant_id', p_tenant_id,
    'brand_name', v_brand_name,
    'sender_name', v_sender_name,
    'from_email', v_domain.from_email_local || '@' || v_domain.domain,
    'from_name', COALESCE(v_domain.from_name, v_sender_name),
    'domain', v_domain.domain
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.resolve_client_id_by_email(_email text)
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT id FROM public.clients
  WHERE email IS NOT NULL AND lower(email) = lower(_email)
  ORDER BY created_at ASC LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.revoke_platform_access(_user_id uuid, _reason text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE _revoked_roles text[];
BEGIN
  IF NOT (public.has_role(auth.uid(), 'admin'::public.app_role) OR public.is_platform_owner()) THEN
    RAISE EXCEPTION 'Admin privileges required';
  END IF;
  IF EXISTS (
    SELECT 1 FROM public.app_settings_owner o
    JOIN auth.users u ON u.email = o.owner_email WHERE u.id = _user_id
  ) THEN
    RAISE EXCEPTION 'Cannot revoke platform owner';
  END IF;

  SELECT array_agg(role::text) INTO _revoked_roles FROM public.user_roles
   WHERE user_id = _user_id
     AND role::text IN ('admin','coach','sales_rep','broker','broker_team_member','cs_rep','finance','viewer','moderator','owner');

  DELETE FROM public.user_roles
   WHERE user_id = _user_id
     AND role::text IN ('admin','coach','sales_rep','broker','broker_team_member','cs_rep','finance','viewer','moderator','owner');
  DELETE FROM public.tenant_members WHERE user_id = _user_id;

  INSERT INTO public.audit_logs (user_id, entity, action, entity_id, data)
  VALUES (auth.uid(), 'user', 'revoke_platform_access', _user_id,
          jsonb_build_object('revoked_by', auth.uid(), 'reason', _reason));

  INSERT INTO public.paige_audit_log
    (actor_user_id, actor_role, action, target_type, target_id, payload)
  VALUES (auth.uid(), 'admin', 'role:revoke', 'user_role', _user_id,
          jsonb_build_object('revoked_roles', COALESCE(_revoked_roles, ARRAY[]::text[]), 'reason', _reason));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.revoke_platform_access(_user_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NOT (public.has_role(auth.uid(), 'admin'::app_role) OR public.is_platform_owner()) THEN
    RAISE EXCEPTION 'Admin privileges required';
  END IF;
  IF EXISTS (
    SELECT 1 FROM public.app_settings_owner o
    JOIN auth.users u ON u.email = o.owner_email WHERE u.id = _user_id
  ) THEN
    RAISE EXCEPTION 'Cannot revoke platform owner';
  END IF;
  DELETE FROM public.user_roles
   WHERE user_id = _user_id
     AND role::text IN ('admin','coach','sales_rep','broker','broker_team_member','cs_rep','finance','viewer','moderator','owner');
  DELETE FROM public.tenant_members WHERE user_id = _user_id;
  INSERT INTO public.audit_logs (user_id, entity, action, entity_id, data)
  VALUES (auth.uid(), 'user', 'revoke_platform_access', _user_id,
          jsonb_build_object('revoked_by', auth.uid()));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.scan_soft_subagents_for_tool_refs()
 RETURNS TABLE(out_slug text, out_pattern text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  r record;
  patterns text[] := ARRAY[
    '\m(call|invoke|use|run|execute|query|fetch|delegate(\s+to)?)\s+(the\s+)?(list_|run_|get_|verify_|search_|create_|update_|delete_|advance_|bulk_|broadcast_|send_|propose_|tool_)[a-z_]+',
    '\m(list_|run_|get_|verify_|search_|create_|update_|delete_|advance_|bulk_|broadcast_|send_|propose_|tool_)[a-z_]+\s*\(',
    '\m(MCP|tool[_\s]?invoke|tool[_\s]?search|tool[_\s]?registry)\M',
    '\mcall\s+(any|the|its?)\s+tools?\M'
  ];
  p text; m text;
BEGIN
  FOR r IN
    SELECT s.slug AS sub_slug, s.system_prompt
      FROM public.paige_subagents s
     WHERE s.runtime = 'soft' AND s.enabled = true
  LOOP
    FOREACH p IN ARRAY patterns LOOP
      m := substring(r.system_prompt FROM p);
      IF m IS NOT NULL THEN
        UPDATE public.paige_subagents AS sa
           SET enabled = false,
               auto_disabled_reason = format('soft_runtime_tool_call_detected (pattern matched: %s)', left(m, 120))
         WHERE sa.slug = r.sub_slug;

        INSERT INTO public.paige_admin_notifications (severity, title, body, scope)
        VALUES (
          'warning',
          format('Sub-agent %s auto-disabled', r.sub_slug),
          format('Soft sub-agent %s was auto-disabled by the §124 v2 tool-reference scan. Matched fragment: %s', r.sub_slug, left(m, 200)),
          'admin'
        );

        out_slug := r.sub_slug; out_pattern := m;
        RETURN NEXT;
        EXIT;
      END IF;
    END LOOP;
  END LOOP;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.set_broker_team_default_permissions()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  -- Only auto-set on insert, OR when role changes and permissions weren't explicitly altered
  IF TG_OP = 'INSERT' OR (TG_OP = 'UPDATE' AND OLD.role IS DISTINCT FROM NEW.role) THEN
    NEW.permissions := CASE NEW.role
      WHEN 'lead_broker' THEN
        '{"can_add_clients": true, "can_remove_clients": true, "can_run_sessions": true, "can_share_summaries": true, "can_manage_team": true, "can_view_commissions": false}'::jsonb
      WHEN 'advisor' THEN
        '{"can_add_clients": false, "can_remove_clients": false, "can_run_sessions": true, "can_share_summaries": true, "can_manage_team": false, "can_view_commissions": false}'::jsonb
      WHEN 'assistant' THEN
        '{"can_add_clients": false, "can_remove_clients": false, "can_run_sessions": false, "can_share_summaries": false, "can_manage_team": false, "can_view_commissions": false}'::jsonb
      ELSE NEW.permissions
    END;
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.set_journey_stage(_contact_id uuid, _stage_slug text, _source_event text DEFAULT 'manual'::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _to_id integer;
  _from_id integer;
  _is_staff boolean := false;
BEGIN
  IF auth.uid() IS NOT NULL THEN
    _is_staff := public.has_role(auth.uid(), 'admin'::public.app_role)
              OR public.has_role(auth.uid(), 'coach'::public.app_role);
  END IF;
  IF NOT _is_staff AND auth.role() <> 'service_role' THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;

  SELECT id INTO _to_id FROM public.paige_journey_stages WHERE slug = _stage_slug;
  IF _to_id IS NULL THEN
    RAISE EXCEPTION 'Unknown journey stage: %', _stage_slug;
  END IF;

  SELECT journey_stage_id INTO _from_id FROM public.clients WHERE id = _contact_id;
  IF _from_id IS NOT DISTINCT FROM _to_id THEN
    RETURN jsonb_build_object('ok', true, 'unchanged', true, 'stage_id', _to_id);
  END IF;

  UPDATE public.clients
     SET journey_stage_id = _to_id,
         journey_stage_entered_at = now()
   WHERE id = _contact_id;

  INSERT INTO public.paige_journey_stage_transitions
    (contact_id, from_stage_id, to_stage_id, transitioned_by, source_event)
  VALUES
    (_contact_id, _from_id, _to_id, auth.uid(), COALESCE(_source_event, 'manual'));

  RETURN jsonb_build_object('ok', true, 'from_stage_id', _from_id, 'to_stage_id', _to_id);
END;
$function$
;

