$function$
;

CREATE OR REPLACE FUNCTION public.start_client_impersonation(p_contact_id uuid)
 RETURNS TABLE(contact_id uuid, linked_user_id uuid, client_name text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller uuid := auth.uid();
  v_row    record;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'not authenticated';
  END IF;

  IF NOT public.can_access_contact(v_caller, p_contact_id) THEN
    RAISE EXCEPTION 'not authorized for this contact';
  END IF;

  SELECT c.id, c.linked_user_id, c.agreement_signed_at, c.onboarding_stage,
         COALESCE(NULLIF(TRIM(CONCAT_WS(' ', c.first_name, c.last_name)), ''), c.email, 'Client') AS name
    INTO v_row
  FROM public.clients c
  WHERE c.id = p_contact_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'contact not found';
  END IF;

  IF v_row.linked_user_id IS NULL THEN
    RAISE EXCEPTION 'client has not accepted their invite yet';
  END IF;

  IF v_row.agreement_signed_at IS NULL THEN
    RAISE EXCEPTION 'client has not signed the agreement yet';
  END IF;

  IF v_row.onboarding_stage <> 'completed' THEN
    RAISE EXCEPTION 'client has not completed onboarding (stage: %)', v_row.onboarding_stage;
  END IF;

  INSERT INTO public.audit_logs (user_id, action, entity, entity_id, data)
  VALUES (v_caller, 'impersonation.start', 'client', v_row.id,
          jsonb_build_object('linked_user_id', v_row.linked_user_id, 'client_name', v_row.name));

  contact_id := v_row.id;
  linked_user_id := v_row.linked_user_id;
  client_name := v_row.name;
  RETURN NEXT;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.suspend_user(_user_id uuid, _reason text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NOT (public.is_platform_owner() OR public.has_role(auth.uid(), 'admin')) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  IF _user_id IS NULL OR _user_id = auth.uid() THEN
    RAISE EXCEPTION 'cannot suspend self';
  END IF;

  UPDATE public.profiles
    SET suspended_at = now(),
        suspended_reason = _reason,
        suspended_by = auth.uid(),
        updated_at = now()
    WHERE id = _user_id;

  INSERT INTO public.paige_audit_log (actor_user_id, action, target_type, target_id, metadata)
  VALUES (auth.uid(), 'suspend_user', 'user', _user_id, jsonb_build_object('reason', _reason));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.sync_assigned_coach_to_coach_clients()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.assigned_coach_user_id IS NOT NULL
     AND NEW.linked_user_id IS NOT NULL
     AND (
       TG_OP = 'INSERT'
       OR OLD.assigned_coach_user_id IS DISTINCT FROM NEW.assigned_coach_user_id
       OR OLD.linked_user_id IS DISTINCT FROM NEW.linked_user_id
     )
  THEN
    INSERT INTO public.coach_clients (coach_user_id, client_user_id, status)
    VALUES (NEW.assigned_coach_user_id, NEW.linked_user_id, 'active')
    ON CONFLICT (coach_user_id, client_user_id) DO NOTHING;
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.sync_assignment_to_client_denorm()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _target uuid;
BEGIN
  IF NEW.contact_id IS NULL THEN RETURN NEW; END IF;
  -- Prefer rep_user_id; else resolve via coach -> clients.linked_user_id
  _target := NEW.rep_user_id;
  IF _target IS NULL AND NEW.coach_id IS NOT NULL THEN
    SELECT linked_user_id INTO _target FROM public.clients WHERE id = NEW.coach_id;
  END IF;
  IF _target IS NULL OR NEW.active IS DISTINCT FROM TRUE THEN
    RETURN NEW;
  END IF;

  IF NEW.assigned_role = 'lead_owner' THEN
    UPDATE public.clients SET lead_owner_user_id = _target, updated_at = now()
     WHERE id = NEW.contact_id AND lead_owner_user_id IS DISTINCT FROM _target;
  ELSIF NEW.assigned_role = 'cs_primary' THEN
    UPDATE public.clients SET cs_primary_user_id = _target, updated_at = now()
     WHERE id = NEW.contact_id AND cs_primary_user_id IS DISTINCT FROM _target;
  ELSIF NEW.assigned_role IN ('coach','coach_btf','coach_dfy','coach_vip') THEN
    UPDATE public.clients SET assigned_coach_user_id = _target, updated_at = now()
     WHERE id = NEW.contact_id AND assigned_coach_user_id IS DISTINCT FROM _target;
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.sync_feature_request_vote_count()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF TG_OP = 'INSERT' THEN
    UPDATE public.feature_requests
    SET vote_count = vote_count + 1, updated_at = now()
    WHERE id = NEW.feature_request_id;
    RETURN NEW;
  ELSIF TG_OP = 'DELETE' THEN
    UPDATE public.feature_requests
    SET vote_count = GREATEST(vote_count - 1, 0), updated_at = now()
    WHERE id = OLD.feature_request_id;
    RETURN OLD;
  END IF;
  RETURN NULL;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.sync_tenant_member_to_user_roles()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _new_role app_role;
  _old_role app_role;
BEGIN
  IF TG_OP IN ('INSERT','UPDATE') AND NEW.status = 'active' THEN
    _new_role := public.map_tenant_role_to_app_role(NEW.role);
    IF _new_role IS NOT NULL AND EXISTS (SELECT 1 FROM auth.users u WHERE u.id = NEW.user_id) THEN
      INSERT INTO public.user_roles (user_id, role)
      VALUES (NEW.user_id, _new_role)
      ON CONFLICT (user_id, role) DO NOTHING;
    END IF;
  END IF;

  IF TG_OP = 'UPDATE' THEN
    _old_role := public.map_tenant_role_to_app_role(OLD.role);
    IF _old_role IS NOT NULL
       AND (OLD.role <> NEW.role OR NEW.status <> 'active')
       AND _old_role <> COALESCE(public.map_tenant_role_to_app_role(NEW.role), 'user'::app_role)
    THEN
      IF NOT EXISTS (
        SELECT 1 FROM public.tenant_members tm
        WHERE tm.user_id = OLD.user_id AND tm.status = 'active'
          AND tm.id <> OLD.id
          AND public.map_tenant_role_to_app_role(tm.role) = _old_role
      ) THEN
        DELETE FROM public.user_roles WHERE user_id = OLD.user_id AND role = _old_role;
      END IF;
    END IF;
  END IF;

  IF TG_OP = 'DELETE' THEN
    _old_role := public.map_tenant_role_to_app_role(OLD.role);
    IF _old_role IS NOT NULL THEN
      IF NOT EXISTS (
        SELECT 1 FROM public.tenant_members tm
        WHERE tm.user_id = OLD.user_id AND tm.status = 'active'
          AND public.map_tenant_role_to_app_role(tm.role) = _old_role
      ) THEN
        DELETE FROM public.user_roles WHERE user_id = OLD.user_id AND role = _old_role;
      END IF;
    END IF;
    RETURN OLD;
  END IF;

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.sync_user_business_limit_from_subscription()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _new_default integer;
  _existing_max integer;
BEGIN
  _new_default := public.default_max_businesses_for_plan(NEW.plan_slug);

  INSERT INTO public.user_business_limits (user_id, max_businesses)
  VALUES (NEW.user_id, _new_default)
  ON CONFLICT (user_id) DO NOTHING;

  SELECT max_businesses INTO _existing_max
  FROM public.user_business_limits
  WHERE user_id = NEW.user_id;

  -- Upgrade automatically; never downgrade an admin-granted higher limit.
  IF _existing_max IS NOT NULL AND _new_default > _existing_max THEN
    UPDATE public.user_business_limits
    SET max_businesses = _new_default,
        updated_at = now()
    WHERE user_id = NEW.user_id;
  END IF;

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.sync_user_role_to_tenant_member()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _tenant_id uuid;
  _tenant_role public.tenant_role;
BEGIN
  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;

  IF NEW.role = 'super_admin'::public.app_role THEN
    RETURN NEW;
  END IF;

  _tenant_id := public.current_user_tenant_id();
  IF _tenant_id IS NULL THEN
    RETURN NEW;
  END IF;

  IF NOT (public.is_platform_owner() OR public.is_tenant_admin(_tenant_id)) THEN
    RETURN NEW;
  END IF;

  _tenant_role := public.map_app_role_to_tenant_role(NEW.role);

  INSERT INTO public.tenant_members (tenant_id, user_id, role, status, invited_at, joined_at)
  VALUES (_tenant_id, NEW.user_id, _tenant_role, 'active', now(), now())
  ON CONFLICT (tenant_id, user_id) DO UPDATE
    SET role = CASE
          WHEN public.tenant_members.role = 'owner'::public.tenant_role THEN public.tenant_members.role
          WHEN EXCLUDED.role = 'admin'::public.tenant_role THEN 'admin'::public.tenant_role
          WHEN EXCLUDED.role = 'coach'::public.tenant_role
               AND public.tenant_members.role NOT IN ('admin'::public.tenant_role, 'owner'::public.tenant_role)
            THEN 'coach'::public.tenant_role
          ELSE public.tenant_members.role
        END,
        status = 'active',
        joined_at = COALESCE(public.tenant_members.joined_at, now()),
        updated_at = now();

  UPDATE public.profiles
     SET active_tenant_id = _tenant_id
   WHERE user_id = NEW.user_id
     AND active_tenant_id IS NULL;

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.tenant_feature_enabled(_tenant_id uuid, _feature text)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE _row public.tenant_features%ROWTYPE;
BEGIN
  IF _tenant_id IS NULL OR _feature IS NULL THEN RETURN false; END IF;
  SELECT * INTO _row FROM public.tenant_features WHERE tenant_id = _tenant_id;
  IF NOT FOUND THEN RETURN false; END IF;
  RETURN CASE _feature
    WHEN 'credit_services_enabled' THEN _row.credit_services_enabled
    WHEN 'coaching_enabled'        THEN _row.coaching_enabled
    WHEN 'legal_services_enabled'  THEN _row.legal_services_enabled
    ELSE false END;
END; $function$
;

CREATE OR REPLACE FUNCTION public.tenant_has_feature(_feature text)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT COALESCE(
    (SELECT (features ->> _feature)::boolean
       FROM public.tenants
      WHERE id = public.current_user_tenant_id()),
    false
  );
$function$
;

CREATE OR REPLACE FUNCTION public.tenant_sender_identity(_tenant_id uuid)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT jsonb_build_object(
    'tenant_id',     t.id,
    'tenant_name',   t.name,
    'tenant_slug',   t.slug,
    'from_name',     COALESCE(
                       NULLIF(t.brand ->> 'from_name', ''),
                       NULLIF(d.from_name, ''),
                       t.name,
                       'Paige Agent AI'
                     ),
    'support_email', t.brand ->> 'support_email',
    'from_address',  COALESCE(
                       NULLIF(t.brand ->> 'from_address', ''),
                       CASE
                         WHEN d.domain IS NOT NULL
                           THEN COALESCE(NULLIF(d.from_email_local, ''), 'noreply') || '@' || d.domain
                         ELSE 'noreply@mail.mogulmakeracademy.com'
                       END
                     ),
    'reply_to',      COALESCE(t.brand ->> 'support_email', 'support@paigeagent.ai')
  )
  FROM public.tenants t
  LEFT JOIN LATERAL (
    SELECT domain, from_email_local, from_name
    FROM public.tenant_email_domains
    WHERE tenant_id = t.id
      AND COALESCE(status, '') = 'verified'
    ORDER BY is_default DESC, updated_at DESC NULLS LAST
    LIMIT 1
  ) d ON true
  WHERE t.id = _tenant_id;
$function$
;

CREATE OR REPLACE FUNCTION public.tenant_set_account_number_prefix()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  base_prefix TEXT;
  candidate TEXT;
  suffix INT := 0;
BEGIN
  IF NEW.account_number_prefix IS NOT NULL AND length(trim(NEW.account_number_prefix)) > 0 THEN
    NEW.account_number_prefix := upper(regexp_replace(NEW.account_number_prefix, '[^A-Za-z0-9]', '', 'g'));
    RETURN NEW;
  END IF;

  -- Derive from slug: take initials of hyphenated words, else first 3-5 chars
  IF NEW.slug IS NULL OR length(trim(NEW.slug)) = 0 THEN
    base_prefix := 'TEN';
  ELSIF position('-' in NEW.slug) > 0 THEN
    -- Multi-word slug: take first letter of each word (e.g. "mogul-maker-academy" -> "MMA")
    SELECT upper(string_agg(left(part, 1), '')) INTO base_prefix
    FROM unnest(string_to_array(NEW.slug, '-')) AS part
    WHERE length(part) > 0;
    -- If too short (< 2 chars), pad from first word
    IF base_prefix IS NULL OR length(base_prefix) < 2 THEN
      base_prefix := upper(left(regexp_replace(NEW.slug, '[^A-Za-z0-9]', '', 'g'), 4));
    END IF;
  ELSE
    -- Single-word slug: take first 3-4 chars uppercased
    base_prefix := upper(left(regexp_replace(NEW.slug, '[^A-Za-z0-9]', '', 'g'), 4));
  END IF;

  -- Ensure uniqueness across tenants (append numeric suffix if collision)
  candidate := base_prefix;
  WHILE EXISTS (SELECT 1 FROM public.tenants WHERE account_number_prefix = candidate AND id <> NEW.id) LOOP
    suffix := suffix + 1;
    candidate := base_prefix || suffix::text;
  END LOOP;

  NEW.account_number_prefix := candidate;
  RETURN NEW;
END;
$function$
;

