CREATE OR REPLACE FUNCTION public.trigger_business_credit_sync(_user_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _result json;
BEGIN
  -- Verify user owns at least one business
  IF NOT EXISTS (
    SELECT 1 FROM public.businesses 
    WHERE owner_user_id = _user_id 
    AND ein IS NOT NULL
  ) THEN
    RAISE EXCEPTION 'No businesses with EIN found for user';
  END IF;

  -- This would normally call the edge function, but for now we just log it
  INSERT INTO public.audit_logs (user_id, entity, action, data)
  VALUES (
    _user_id,
    'business_credit',
    'manual_sync_triggered',
    jsonb_build_object('triggered_at', now())
  );

  RETURN json_build_object(
    'success', true,
    'message', 'Business credit sync scheduled'
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.trigger_readiness_scan_cron()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_url text;
  v_key text;
BEGIN
  SELECT value INTO v_url FROM public._internal_secrets WHERE key = 'supabase_functions_base_url';
  IF v_url IS NULL THEN
    RAISE WARNING 'trigger_readiness_scan_cron: supabase_functions_base_url secret missing; skipping';
    RETURN;
  END IF;

  SELECT value INTO v_key FROM public._internal_secrets WHERE key = 'readiness_scan_service_role_key';
  IF v_key IS NULL THEN
    SELECT value INTO v_key FROM public._internal_secrets WHERE key = 'supabase_service_role_key';
  END IF;
  IF v_key IS NULL THEN
    RAISE WARNING 'trigger_readiness_scan_cron: service role key not seeded; skipping';
    RETURN;
  END IF;

  PERFORM net.http_post(
    url := rtrim(v_url, '/') || '/readiness-scan',
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'Authorization', 'Bearer ' || v_key
    ),
    body := jsonb_build_object('trigger_source', 'cron')
  );
END;
$function$
;

