-- §11 VIEWS MATVIEWS
-- =============================================================================

CREATE MATERIALIZED VIEW IF NOT EXISTS public.analytics_daily_summary AS  WITH days AS (
         SELECT generate_series((CURRENT_DATE - '180 days'::interval)::date::timestamp with time zone, CURRENT_DATE::timestamp with time zone, '1 day'::interval)::date AS date
        ), signups AS (
         SELECT date_trunc('day'::text, profiles.created_at)::date AS date,
            count(*)::integer AS cnt
           FROM profiles
          GROUP BY (date_trunc('day'::text, profiles.created_at)::date)
        ), active AS (
         SELECT date_trunc('day'::text, analytics_events.created_at)::date AS date,
            count(DISTINCT analytics_events.user_id)::integer AS cnt
           FROM analytics_events
          WHERE analytics_events.user_id IS NOT NULL
          GROUP BY (date_trunc('day'::text, analytics_events.created_at)::date)
        ), paige AS (
         SELECT date_trunc('day'::text, analytics_events.created_at)::date AS date,
            count(*)::integer AS cnt
           FROM analytics_events
          WHERE analytics_events.event_name = 'paige_session_start'::text
          GROUP BY (date_trunc('day'::text, analytics_events.created_at)::date)
        ), voice AS (
         SELECT date_trunc('day'::text, analytics_events.created_at)::date AS date,
            count(*)::integer AS cnt
           FROM analytics_events
          WHERE analytics_events.event_name = 'voice_session_start'::text
          GROUP BY (date_trunc('day'::text, analytics_events.created_at)::date)
        ), credit AS (
         SELECT date_trunc('day'::text, credit_report_uploads.created_at)::date AS date,
            count(*)::integer AS cnt
           FROM credit_report_uploads
          GROUP BY (date_trunc('day'::text, credit_report_uploads.created_at)::date)
        ), funding AS (
         SELECT date_trunc('day'::text, analytics_events.created_at)::date AS date,
            count(*)::integer AS cnt
           FROM analytics_events
          WHERE analytics_events.event_name = ANY (ARRAY['funding_application_submitted'::text, 'funding_match_viewed'::text])
          GROUP BY (date_trunc('day'::text, analytics_events.created_at)::date)
        ), new_mrr AS (
         SELECT date_trunc('day'::text, analytics_events.created_at)::date AS date,
            COALESCE(sum((analytics_events.properties ->> 'amount'::text)::numeric), 0::numeric) AS amt
           FROM analytics_events
          WHERE analytics_events.event_name = ANY (ARRAY['subscription_started'::text, 'broker_subscription_started'::text, 'trial_started'::text])
          GROUP BY (date_trunc('day'::text, analytics_events.created_at)::date)
        ), churn_mrr AS (
         SELECT date_trunc('day'::text, analytics_events.created_at)::date AS date,
            COALESCE(sum((analytics_events.properties ->> 'amount'::text)::numeric), 0::numeric) AS amt
           FROM analytics_events
          WHERE analytics_events.event_name = 'subscription_cancelled'::text
          GROUP BY (date_trunc('day'::text, analytics_events.created_at)::date)
        )
 SELECT d.date,
    COALESCE(s.cnt, 0) AS new_signups,
    COALESCE(a.cnt, 0) AS active_users,
    COALESCE(p.cnt, 0) AS paige_sessions,
    COALESCE(v.cnt, 0) AS voice_sessions,
    COALESCE(c.cnt, 0) AS credit_uploads,
    COALESCE(f.cnt, 0) AS funding_applications,
    COALESCE(nm.amt, 0::numeric) AS new_mrr,
    COALESCE(cm.amt, 0::numeric) AS churned_mrr
   FROM days d
     LEFT JOIN signups s ON s.date = d.date
     LEFT JOIN active a ON a.date = d.date
     LEFT JOIN paige p ON p.date = d.date
     LEFT JOIN voice v ON v.date = d.date
     LEFT JOIN credit c ON c.date = d.date
     LEFT JOIN funding f ON f.date = d.date
     LEFT JOIN new_mrr nm ON nm.date = d.date
     LEFT JOIN churn_mrr cm ON cm.date = d.date
  ORDER BY d.date;
CREATE MATERIALIZED VIEW IF NOT EXISTS public.analytics_feature_usage AS  SELECT COALESCE(properties ->> 'feature'::text, event_name) AS feature_name,
    count(*)::integer AS usage_count,
    count(DISTINCT user_id)::integer AS unique_users,
    date_trunc('day'::text, created_at)::date AS date
   FROM analytics_events
  WHERE event_name = ANY (ARRAY['feature_visit'::text, 'paige_session_start'::text, 'voice_session_start'::text, 'credit_alert_viewed'::text, 'funding_match_viewed'::text, 'lender_searched'::text, 'entity_diagram_generated'::text, 'web_search_triggered'::text, 'rag_retrieval_triggered'::text])
  GROUP BY (COALESCE(properties ->> 'feature'::text, event_name)), (date_trunc('day'::text, created_at)::date);
CREATE OR REPLACE VIEW public._bank_rollup AS  SELECT contact_id,
    count(*) AS bank_connections,
    count(*) FILTER (WHERE status = 'active'::text) AS bank_connections_active,
    max(last_synced_at) AS last_bank_sync_at
   FROM paige_bank_connections
  GROUP BY contact_id;
CREATE OR REPLACE VIEW public._latest_cash_flow AS  SELECT DISTINCT ON (contact_id) contact_id,
    period_start,
    period_end,
    total_deposits_cents,
    total_withdrawals_cents,
    avg_daily_balance_cents,
    runway_days,
    funding_readiness_score,
    generated_at
   FROM paige_cash_flow_snapshots
  ORDER BY contact_id, generated_at DESC NULLS LAST;
CREATE OR REPLACE VIEW public._latest_owner_credit AS  SELECT DISTINCT ON (contact_id) contact_id,
    bureau,
    score,
    pulled_at
   FROM paige_owner_credit_snapshots
  ORDER BY contact_id, pulled_at DESC NULLS LAST;
CREATE OR REPLACE VIEW public._signature_rollup AS  SELECT contact_id,
    count(*) FILTER (WHERE status = ANY (ARRAY['sent'::paige_envelope_status, 'delivered'::paige_envelope_status])) AS envelopes_pending,
    count(*) FILTER (WHERE status = 'completed'::paige_envelope_status) AS envelopes_completed,
    count(*) AS envelopes_total,
    max(signed_at) AS last_signed_at
   FROM paige_signature_envelopes
  WHERE contact_id IS NOT NULL
  GROUP BY contact_id;
CREATE OR REPLACE VIEW public.coach_client_profiles_safe AS  SELECT id,
    user_id,
    full_name,
    avatar_url,
    pme_phase,
    dashboard_mode,
    onboarding_completed,
    onboarding_step,
    intake_completed,
    intake_completed_at,
    primary_goal,
    primary_goal_category,
    goal_timeline,
    experience_level,
    is_complimentary,
    has_broker_access,
    active_tenant_id,
    business_name,
    work_email,
    website_url,
    staff_notes,
    suspended_at,
    suspended_reason,
    created_at,
    updated_at
   FROM profiles p
  WHERE user_id = auth.uid() OR has_role(auth.uid(), 'admin'::app_role) OR has_role(auth.uid(), 'coach'::app_role) OR has_role(auth.uid(), 'super_admin'::app_role) OR is_platform_owner() OR (EXISTS ( SELECT 1
           FROM coach_clients cc
          WHERE cc.coach_user_id = auth.uid() AND cc.client_user_id = p.user_id AND cc.status = 'active'::text));
CREATE OR REPLACE VIEW public.contact_deal_rollup AS  SELECT c.id AS contact_id,
    count(d.id) FILTER (WHERE d.status = 'open'::text) AS open_deals,
    count(d.id) FILTER (WHERE d.status = 'won'::text) AS won_deals,
    COALESCE(sum(d.value_cents) FILTER (WHERE d.status = 'open'::text), 0::numeric) AS open_value_cents,
    COALESCE(sum(d.value_cents) FILTER (WHERE d.status = 'won'::text), 0::numeric) AS won_value_cents
   FROM clients c
     LEFT JOIN deals d ON d.contact_client_id = c.id
  GROUP BY c.id;
CREATE OR REPLACE VIEW public.paige_approval_queue_v AS  SELECT a.id,
    a.type,
    a.category,
    a.status,
    a.priority,
    a.risk_level,
    a.summary,
    a.source,
    a.requires_role,
    a.tenant_id,
    a.contact_id,
    a.conversation_id,
    a.assigned_to_user_id,
    a.submitted_by_user_id,
    a.visible_to_roles,
    a.sla_due_at,
    a.created_at,
    a.reviewed_at,
    a.sent_at,
    a.draft_content,
    a.metadata,
    c.first_name AS contact_first_name,
    c.last_name AS contact_last_name,
    c.email AS contact_email,
    c.lifecycle_stage AS contact_lifecycle_stage,
    EXTRACT(epoch FROM now() - a.created_at)::integer AS age_seconds,
        CASE
            WHEN a.status <> 'pending'::text THEN 'closed'::text
            WHEN a.sla_due_at IS NULL THEN 'unscheduled'::text
            WHEN a.sla_due_at < now() THEN 'overdue'::text
            WHEN a.sla_due_at < (now() + '02:00:00'::interval) THEN 'due_soon'::text
            ELSE 'on_track'::text
        END AS sla_state
   FROM paige_pending_approvals a
     LEFT JOIN clients c ON c.id = a.contact_id;
CREATE OR REPLACE VIEW public.paige_unassigned_queue AS  SELECT id,
    email,
    first_name,
    last_name,
    tier,
    ghl_contact_id,
    created_at,
    last_mirrored_at,
    EXTRACT(epoch FROM now() - created_at) / 3600.0 AS unassigned_for_hours,
        CASE tier
            WHEN 'vip'::text THEN 1
            WHEN 'premium'::text THEN 2
            WHEN 'internal'::text THEN 3
            WHEN 'staff'::text THEN 3
            WHEN 'standard'::text THEN 4
            WHEN 'lead'::text THEN 5
            ELSE 6
        END AS priority_rank
   FROM clients c
  WHERE status <> 'archived'::text AND NOT (EXISTS ( SELECT 1
           FROM paige_coach_assignments pca
          WHERE pca.contact_id = c.id AND pca.active = true AND (pca.assigned_role = ANY (ARRAY['lead_owner'::text, 'cs_primary'::text])) AND pca.rep_user_id IS NOT NULL))
  ORDER BY (
        CASE tier
            WHEN 'vip'::text THEN 1
            WHEN 'premium'::text THEN 2
            WHEN 'internal'::text THEN 3
            WHEN 'staff'::text THEN 3
            WHEN 'standard'::text THEN 4
            WHEN 'lead'::text THEN 5
            ELSE 6
        END), created_at DESC;
CREATE OR REPLACE VIEW public.v_affiliate_stats AS  SELECT ap.id AS affiliate_id,
    ap.user_id,
    p.full_name,
    NULL::text AS email,
    ap.referral_code,
    t.tier_key,
    t.display_name AS tier_name,
    t.commission_rate,
    ap.active,
    COALESCE(clicks.n, 0::bigint) AS clicks,
    COALESCE(signups.n, 0::bigint) AS signups,
    COALESCE(paid.n, 0::bigint) AS paid_conversions,
    COALESCE(paid.commission_owed_cents, 0::bigint) AS commission_owed_cents,
    COALESCE(payments.paid_ytd_cents, 0::bigint) AS commission_paid_ytd_cents
   FROM affiliate_profiles ap
     LEFT JOIN profiles p ON p.user_id = ap.user_id
     LEFT JOIN affiliate_commission_tiers t ON t.id = ap.commission_tier_id
     LEFT JOIN LATERAL ( SELECT count(*) AS n
           FROM referral_clicks rc
          WHERE rc.affiliate_id = ap.id) clicks ON true
     LEFT JOIN LATERAL ( SELECT count(DISTINCT rv.referred_user_id) AS n
           FROM referral_conversions rv
          WHERE rv.affiliate_id = ap.id) signups ON true
     LEFT JOIN LATERAL ( SELECT count(*) AS n,
            COALESCE(sum(rv.commission_cents) FILTER (WHERE rv.status = 'attributed'::text), 0::bigint) AS commission_owed_cents
           FROM referral_conversions rv
          WHERE rv.affiliate_id = ap.id) paid ON true
     LEFT JOIN LATERAL ( SELECT COALESCE(sum(cp.amount_cents), 0::bigint) AS paid_ytd_cents
           FROM commission_payments cp
          WHERE cp.affiliate_id = ap.id AND cp.status = 'paid'::text AND cp.period_end >= date_trunc('year'::text, now())) payments ON true;
CREATE OR REPLACE VIEW public.v_referral_funnel_daily AS  WITH days AS (
         SELECT generate_series(date_trunc('day'::text, now() - '90 days'::interval), date_trunc('day'::text, now()), '1 day'::interval)::date AS day
        )
 SELECT day,
    COALESCE(( SELECT count(*) AS count
           FROM referral_clicks
          WHERE date_trunc('day'::text, referral_clicks.clicked_at)::date = d.day), 0::bigint) AS clicks,
    COALESCE(( SELECT count(DISTINCT referral_conversions.referred_user_id) AS count
           FROM referral_conversions
          WHERE date_trunc('day'::text, referral_conversions.converted_at)::date = d.day), 0::bigint) AS signups,
    COALESCE(( SELECT count(*) AS count
           FROM referral_conversions
          WHERE date_trunc('day'::text, referral_conversions.converted_at)::date = d.day AND referral_conversions.status = 'attributed'::text), 0::bigint) AS paid
   FROM days d
  ORDER BY day;
CREATE OR REPLACE VIEW public.contact_readiness_rollup AS  SELECT c.id AS contact_id,
    c.linked_user_id,
    c.assigned_coach_user_id,
    c.first_name,
    c.last_name,
    c.email,
    c.entity_name,
    c.lifecycle_stage,
    c.funding_goal,
    c.tags,
    c.last_contacted_at,
    oc.bureau AS owner_bureau,
    oc.score AS owner_fico,
    oc.pulled_at AS owner_pulled_at,
    bc.scores AS business_scores,
    bc.last_pulled_at AS business_pulled_at,
    cf.avg_daily_balance_cents,
    cf.runway_days,
    cf.funding_readiness_score AS cash_flow_readiness,
    cf.period_end AS cash_flow_period_end,
    COALESCE(b.bank_connections, 0::bigint) AS bank_connections,
    COALESCE(b.bank_connections_active, 0::bigint) AS bank_connections_active,
    b.last_bank_sync_at,
    COALESCE(s.envelopes_total, 0::bigint) AS envelopes_total,
    COALESCE(s.envelopes_completed, 0::bigint) AS envelopes_completed,
    COALESCE(s.envelopes_pending, 0::bigint) AS envelopes_pending,
    s.last_signed_at,
    frs.overall_score AS stored_overall_score,
    frs.last_calculated_at AS stored_score_at,
    compute_contact_readiness(c.id) AS readiness_score
   FROM clients c
     LEFT JOIN _latest_owner_credit oc ON oc.contact_id = c.id
     LEFT JOIN paige_business_credit_profiles bc ON bc.contact_id = c.id
     LEFT JOIN _latest_cash_flow cf ON cf.contact_id = c.id
     LEFT JOIN _bank_rollup b ON b.contact_id = c.id
     LEFT JOIN _signature_rollup s ON s.contact_id = c.id
     LEFT JOIN funding_readiness_scores frs ON frs.user_id = c.linked_user_id;


