-- §08b MATVIEW INDEXES (relkind=m, applied after §11)
CREATE UNIQUE INDEX idx_analytics_daily_summary_date ON public.analytics_daily_summary USING btree (date);
CREATE UNIQUE INDEX idx_analytics_feature_usage_unique ON public.analytics_feature_usage USING btree (feature_name, date);

-- §09b FUNCTIONS (relation-dependent, 3)
SET check_function_bodies = false;

CREATE OR REPLACE FUNCTION public.get_analytics_daily_summary(_start date DEFAULT ((CURRENT_DATE - '90 days'::interval))::date, _end date DEFAULT CURRENT_DATE)
 RETURNS SETOF analytics_daily_summary
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  if not public.has_role(auth.uid(), 'admin'::public.app_role) then
    raise exception 'Unauthorized';
  end if;
  return query
    select * from public.analytics_daily_summary
    where date between _start and _end
    order by date;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.get_analytics_feature_usage(_start date DEFAULT ((CURRENT_DATE - '90 days'::interval))::date, _end date DEFAULT CURRENT_DATE)
 RETURNS SETOF analytics_feature_usage
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  if not public.has_role(auth.uid(), 'admin'::public.app_role) then
    raise exception 'Unauthorized';
  end if;
  return query
    select * from public.analytics_feature_usage
    where date between _start and _end
    order by date, feature_name;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.unassigned_queue_for_caller()
 RETURNS SETOF paige_unassigned_queue
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _uid uuid := auth.uid();
  _pool text[] := ARRAY[]::text[];
BEGIN
  IF _uid IS NULL THEN RETURN; END IF;

  IF public.has_any_role(_uid, ARRAY['admin','super_admin']::text[]) THEN
    RETURN QUERY SELECT * FROM public.paige_unassigned_queue;
    RETURN;
  END IF;

  IF public.has_role(_uid, 'sales_rep'::app_role) THEN
    _pool := _pool || public.tier_pool_for_role('sales_rep'::app_role);
  END IF;
  IF public.has_role(_uid, 'cs_rep'::app_role) THEN
    _pool := _pool || public.tier_pool_for_role('cs_rep'::app_role);
  END IF;

  IF array_length(_pool, 1) IS NULL THEN RETURN; END IF;

  RETURN QUERY SELECT q.* FROM public.paige_unassigned_queue q WHERE q.tier = ANY(_pool);
END $function$
;


