CREATE POLICY "Active agreement templates readable" ON public.agreement_templates AS PERMISSIVE FOR SELECT TO authenticated USING ((is_active = true));
CREATE POLICY "Actors see their own proposals" ON public.paige_ingestion_proposals AS PERMISSIVE FOR SELECT TO authenticated USING ((actor_user_id = auth.uid()));
CREATE POLICY "Admins and coaches can manage certifications" ON public.business_certifications AS PERMISSIVE FOR ALL TO PUBLIC USING ((has_role(auth.uid(), 'admin'::app_role) OR has_role(auth.uid(), 'coach'::app_role))) WITH CHECK ((has_role(auth.uid(), 'admin'::app_role) OR has_role(auth.uid(), 'coach'::app_role)));
CREATE POLICY "Admins and coaches can read all last_seen rows" ON public.support_ticket_last_seen AS PERMISSIVE FOR SELECT TO PUBLIC USING ((has_role(auth.uid(), 'admin'::app_role) OR has_role(auth.uid(), 'coach'::app_role)));
CREATE POLICY "Admins and coaches can read transitions" ON public.paige_journey_stage_transitions AS PERMISSIVE FOR SELECT TO PUBLIC USING ((has_role(auth.uid(), 'admin'::app_role) OR (has_role(auth.uid(), 'coach'::app_role) AND (contact_id IS NOT NULL) AND can_access_contact(auth.uid(), contact_id))));
CREATE POLICY "Admins and coaches insert funding milestones" ON public.funding_milestones AS PERMISSIVE FOR INSERT TO PUBLIC WITH CHECK ((has_role(auth.uid(), 'admin'::app_role) OR (has_role(auth.uid(), 'coach'::app_role) AND coach_can_access_user(auth.uid(), user_id))));
CREATE POLICY "Admins and coaches insert journey applications" ON public.funding_journey_applications AS PERMISSIVE FOR INSERT TO PUBLIC WITH CHECK ((has_role(auth.uid(), 'admin'::app_role) OR (has_role(auth.uid(), 'coach'::app_role) AND coach_can_access_user(auth.uid(), user_id))));
CREATE POLICY "Admins and coaches insert runs" ON public.paige_workflow_runs AS PERMISSIVE FOR INSERT TO authenticated WITH CHECK (((has_role(auth.uid(), 'admin'::app_role) OR has_role(auth.uid(), 'coach'::app_role)) AND (triggered_by_user_id = auth.uid())));
CREATE POLICY "Admins and coaches mark read" ON public.paige_admin_notifications AS PERMISSIVE FOR UPDATE TO authenticated USING ((has_role(auth.uid(), 'admin'::app_role) OR has_role(auth.uid(), 'coach'::app_role))) WITH CHECK ((has_role(auth.uid(), 'admin'::app_role) OR has_role(auth.uid(), 'coach'::app_role)));
CREATE POLICY "Admins and coaches read NPS" ON public.paige_nps_responses AS PERMISSIVE FOR SELECT TO PUBLIC USING ((has_role(auth.uid(), 'admin'::app_role) OR (has_role(auth.uid(), 'coach'::app_role) AND (contact_id IS NOT NULL) AND can_access_contact(auth.uid(), contact_id))));
CREATE POLICY "Admins and coaches read health" ON public.paige_health_snapshots AS PERMISSIVE FOR SELECT TO PUBLIC USING ((has_role(auth.uid(), 'admin'::app_role) OR (has_role(auth.uid(), 'coach'::app_role) AND (contact_id IS NOT NULL) AND (EXISTS ( SELECT 1
   FROM clients c
  WHERE ((c.id = paige_health_snapshots.contact_id) AND (c.assigned_coach_user_id = auth.uid())))))));
CREATE POLICY "Admins and coaches read referrals" ON public.paige_referrals AS PERMISSIVE FOR SELECT TO PUBLIC USING ((has_role(auth.uid(), 'admin'::app_role) OR (has_role(auth.uid(), 'coach'::app_role) AND (referred_contact_id IS NOT NULL) AND can_access_contact(auth.uid(), referred_contact_id))));
CREATE POLICY "Admins and coaches update all journey applications" ON public.funding_journey_applications AS PERMISSIVE FOR UPDATE TO PUBLIC USING ((has_role(auth.uid(), 'admin'::app_role) OR (has_role(auth.uid(), 'coach'::app_role) AND coach_can_access_user(auth.uid(), user_id)))) WITH CHECK ((has_role(auth.uid(), 'admin'::app_role) OR (has_role(auth.uid(), 'coach'::app_role) AND coach_can_access_user(auth.uid(), user_id))));
