-- =============================================================================

-- §14 COMMENTS
-- =============================================================================

COMMENT ON TABLE public.corporate_entity_registry IS 'Portfolio corporate structure. Referenced by tenant_entity_relationships (§202) and public legal disclosures.';
COMMENT ON TABLE public.kb_query_telemetry IS 'Central telemetry — metadata only. Never store raw query text or document content.';
COMMENT ON TABLE public.platform_invoices IS 'LAYER 1 (Platform Subscriptions Tenant->Paige) per Doctrine §197';
COMMENT ON TABLE public.platform_metered_events IS 'LAYER 3 (Platform Pass-Through Metering End Customer->Paige via Tenant) per Doctrine §197. Always bills tenant wholesale cost regardless of tenant billing_method.';
COMMENT ON TABLE public.platform_metering_reconciliation IS 'LAYER 3 (Platform Pass-Through Metering End Customer->Paige via Tenant) per Doctrine §197. Sole cross-layer bridge to LAYER 1 invoices.';
COMMENT ON TABLE public.platform_subscription_plans IS 'LAYER 1 (Platform Subscriptions Tenant->Paige) per Doctrine §197';
COMMENT ON TABLE public.platform_subscriptions IS 'LAYER 1 (Platform Subscriptions Tenant->Paige) per Doctrine §197';
COMMENT ON TABLE public.platform_usage_events IS 'LAYER 1 (Platform Subscriptions Tenant->Paige) per Doctrine §197';
COMMENT ON TABLE public.tenant_entity_relationships IS 'Doctrine §202: a single contact may hold multiple relationships across portfolio entities. Never duplicate contacts.';
COMMENT ON TABLE public.tenant_knowledge_docs IS 'Tier 2 — per-tenant private KB. RLS isolated. Opt-in share_to_network promotes via admin review to Tier 1 (knowledge_base).';
COMMENT ON TABLE public.tenant_service_subscriptions IS 'LAYER 2 (Tenant Service Offerings End Customer->Tenant) per Doctrine §197';
COMMENT ON TABLE public.tenant_service_usage_events IS 'LAYER 2 (Tenant Service Offerings End Customer->Tenant) per Doctrine §197';
COMMENT ON COLUMN public.businesses.business_email IS 'Dedicated business email used on funding applications and bureau records. Should be on a domain the business owns (not gmail/yahoo/etc).';
COMMENT ON COLUMN public.clients.primary_offer IS 'Primary product/offer this contact is enrolled in or pursuing.';
COMMENT ON COLUMN public.credit_accounts.original_amount IS 'Original loan amount or high credit for installment/auto/mortgage accounts — used for comparable credit projections';
COMMENT ON COLUMN public.credit_negative_items.original_amount IS 'Original amount owed before charge-off or collection';
COMMENT ON COLUMN public.deals.offer_type IS 'Productized offer the contact is buying/considering (e.g. BTF, Premium, VIP, ACCEL, BUILD, FUND).';
COMMENT ON COLUMN public.paige_workflow_runs.langgraph_thread_id IS 'LangGraph thread id returned by MMA OS langgraph-bridge or direct langgraph /runs response.';
COMMENT ON COLUMN public.profiles.consent_data_usage IS 'User actively acknowledged data is never sold';
COMMENT ON COLUMN public.profiles.consent_marketing IS 'Optional marketing email opt-in';
COMMENT ON COLUMN public.profiles.consent_privacy_policy IS 'User actively agreed to Privacy Policy + ToS at signup';
COMMENT ON COLUMN public.profiles.consent_timestamp IS 'When the signup consents were captured';
COMMENT ON COLUMN public.profiles.credit_report_consent IS 'User confirmed credit report data usage disclosures before first upload';
COMMENT ON COLUMN public.profiles.credit_report_consent_timestamp IS 'When credit report consent was captured';
COMMENT ON COLUMN public.profiles.has_broker_access IS 'When true, this user can open the Broker Workspace in addition to their normal role (admin/coach/user).';
COMMENT ON COLUMN public.profiles.is_complimentary IS 'When true, grants the user full Pro-level access regardless of their Stripe subscription. Toggled by admins for team members, beta testers, partners, and VIPs.';
COMMENT ON FUNCTION public.factory_reset_delete_dispute_related(_user_id uuid) IS 'Clears dispute-related records for a user and any linked client rows during factory reset.';
